/**
 * Phase 03A Inventory Index
 *
 * Fast search with normalized terms, synonyms, tags, SKU lookup,
 * typo tolerance, zero-result recovery, and deterministic ranking.
 *
 * Performance: search p95 <100ms at 1K records.
 */

import type {
  Open3dAvailabilityStatus,
  Open3dAssetReadiness,
  Open3dCatalogCategory,
  Open3dConfigurability,
  Open3dCatalogItem,
  Open3dMountingContract,
  Open3dRoomTag,
  Open3dStyleTag,
} from "../catalogTypes";

// ── Synonym map ──

/** Common furniture synonym mappings for search expansion */
const SYNONYM_MAP: Record<string, string[]> = {
  "couch": ["sofa", "loveseat", "sectional"],
  "sofa": ["couch", "loveseat", "settee"],
  "desk": ["workstation", "table", "writing-desk", "computer-desk"],
  "chair": ["seat", "stool", "armchair", "seating"],
  "table": ["desk", "surface", "counter"],
  "storage": ["cabinet", "cupboard", "wardrobe", "closet", "shelf"],
  "bed": ["mattress", "bunk", "cot", "bedframe"],
  "lamp": ["light", "lighting", "luminaire", "fixture"],
  "light": ["lamp", "fixture", "luminaire"],
  "rug": ["carpet", "mat", "floor-covering"],
  "plant": ["greenery", "foliage", "tree"],
  "mirror": ["glass", "reflective"],
  "small": ["compact", "tiny", "mini"],
  "large": ["big", "spacious", "oversized", "xl"],
  "office": ["work", "workplace", "business", "corporate"],
  "home": ["house", "residential", "domestic"],
};

/** Expand a token into synonyms for broader search matching */
function expandSynonyms(token: string): string[] {
  const result: string[] = [token];
  const synonyms = SYNONYM_MAP[token];
  if (synonyms) {
    result.push(...synonyms);
  }
  return result;
}

// ── Tokenization ──

const TOKEN_PATTERN = /[\wÀ-ÿ]+/g;

function tokenize(text: string): string[] {
  const tokens: string[] = [];
  const matches = text.toLowerCase().match(TOKEN_PATTERN);
  if (matches) {
    for (const m of matches) {
      if (m.length >= 2) {
        tokens.push(m);
        // Prefix tokens for typo tolerance (3-char minimum)
        if (m.length > 3) {
          for (let i = 3; i <= m.length; i++) {
            tokens.push(m.slice(0, i));
          }
        }
      }
    }
  }
  return tokens;
}

// ── Relevance scoring ──

interface ScoredItem {
  item: Open3dCatalogItem;
  score: number;
}

function compareCatalogItems(a: Open3dCatalogItem, b: Open3dCatalogItem): number {
  return a.name.localeCompare(b.name)
    || a.sku.localeCompare(b.sku)
    || a.id.localeCompare(b.id);
}

function compareScoredItems(a: ScoredItem, b: ScoredItem): number {
  return (b.score - a.score) || compareCatalogItems(a.item, b.item);
}

/**
 * Compute relevance score with deterministic tie-breaking.
 *
 * Accepts pre-tokenized item tokens (built once during load()) to avoid
 * per-call tokenize() allocations in the search hot path (PLAN-FAIL-012).
 *
 * Ranking priority:
 * 1. Exact SKU match: 100
 * 2. Exact name match: 80
 * 3. Exact slug match: 70
 * 4. Tag match: 50 per tag
 * 5. Name token match: 30 per token
 * 6. Description match: 15 per token
 * 7. Fuzzy prefix match: 5 per token
 * 8. Synonym match: 25 per synonym token
 */
function scoreItem(
  item: Open3dCatalogItem,
  preTokenized: string[],
  queryTokens: string[],
  queryLower: string,
): number {
  let score = 0;

  if (item.sku.toLowerCase() === queryLower) score += 100;
  if (item.name.toLowerCase() === queryLower) score += 80;
  if (item.slug.toLowerCase() === queryLower) score += 70;

  const itemTokens = preTokenized;

  // Expand query with synonyms
  const allQueryTokens = new Set<string>();
  for (const qt of queryTokens) {
    for (const syn of expandSynonyms(qt)) {
      allQueryTokens.add(syn);
    }
  }

  for (const qt of allQueryTokens) {
    if (itemTokens.includes(qt)) {
      if (item.tags.some((t) => t.toLowerCase() === qt)) score += 50;
      else if (item.name.toLowerCase().includes(qt)) score += 30;
      else if (item.description.toLowerCase().includes(qt)) score += 15;
      else if (SYNONYM_MAP[queryTokens[0]]?.includes(qt)) score += 25;
      else score += 10;
    } else {
      // Fuzzy prefix match
      for (const it of itemTokens) {
        if (it.startsWith(qt) || qt.startsWith(it)) {
          score += 5;
          break;
        }
      }
    }
  }

  return score;
}

// ── Typo tolerance ──

/**
 * Simple typo tolerance: generates near-miss tokens by single-character edits.
 * Only applied for queries ≥ 4 characters to avoid overwhelming results.
 */
function generateTypoVariants(token: string): string[] {
  if (token.length < 4) return [];
  const variants: string[] = [];
  // Character swap (adjacent)
  for (let i = 0; i < token.length - 1; i++) {
    const chars = token.split("");
    [chars[i], chars[i + 1]] = [chars[i + 1], chars[i]];
    variants.push(chars.join(""));
  }
  return variants.slice(0, 3); // Limit to 3 variants
}

// ── Search engine ──

export interface InventorySearchOptions {
  /** Max results per page */
  pageSize?: number;
  /** Minimum relevance score to include in results */
  minScore?: number;
  /** Whether to use typo tolerance */
  typoTolerance?: boolean;
  /** Optional category filter applied before ranking */
  category?: Open3dCatalogCategory;
  /** Optional room filter. Matches items containing at least one selected room. */
  roomTags?: Open3dRoomTag[];
  /** Optional style filter. Matches items containing at least one selected style. */
  styleTags?: Open3dStyleTag[];
  /** Optional material filter using normalized material values. */
  material?: string[];
  /** Optional availability filter. */
  availability?: Open3dAvailabilityStatus[];
  /** Optional configurability filter. */
  configurability?: Open3dConfigurability[];
  /** Optional mounting/anchoring filter. */
  mounting?: Open3dMountingContract[];
  /** Optional asset-readiness filter for degraded-state recovery. */
  assetReadiness?: Open3dAssetReadiness[];
  /** Optional dimension range filter in millimetres. */
  dimensionFilter?: {
    /** Minimum width in mm */
    minWidthMm?: number;
    /** Maximum width in mm */
    maxWidthMm?: number;
    /** Minimum depth in mm */
    minDepthMm?: number;
    /** Maximum depth in mm */
    maxDepthMm?: number;
    /** Minimum height in mm */
    minHeightMm?: number;
    /** Maximum height in mm */
    maxHeightMm?: number;
  };
}

export interface InventorySearchResult {
  items: Open3dCatalogItem[];
  totalCount: number;
  /** Original query (for zero-result recovery) */
  query: string;
  /** Whether the search was relaxed due to zero results */
  relaxed: boolean;
  /** Suggested correction if typo detected */
  suggestedCorrection?: string;
}

/**
 * Inventory search engine with synonyms, typo tolerance, and zero-result recovery.
 */
export class InventorySearchIndex {
  private items: Open3dCatalogItem[] = [];
  /**
   * Pre-tokenized item corpus, keyed by item ID.
   * Built once in load() so scoreItem() never calls tokenize() at query time.
   * Fixes PLAN-FAIL-012: per-item tokenization in the hot scoring path.
   */
  private itemTokenCache = new Map<string, string[]>();

  load(items: Open3dCatalogItem[]): void {
    this.items = [...items].sort(compareCatalogItems);
    // Pre-tokenize all items once so search scoring is allocation-free per query.
    this.itemTokenCache.clear();
    for (const item of this.items) {
      this.itemTokenCache.set(
        item.id,
        tokenize(`${item.name} ${item.description} ${item.tags.join(" ")} ${item.sku}`),
      );
    }
  }

  private filterItems(options: InventorySearchOptions): Open3dCatalogItem[] {
    const materialFilter = new Set((options.material ?? []).map((value) => value.toLowerCase()));
    const roomFilter = new Set(options.roomTags ?? []);
    const styleFilter = new Set(options.styleTags ?? []);
    const availabilityFilter = new Set(options.availability ?? []);
    const configurabilityFilter = new Set(options.configurability ?? []);
    const mountingFilter = new Set(options.mounting ?? []);
    const assetReadinessFilter = new Set(options.assetReadiness ?? []);
    const dim = options.dimensionFilter;

    return this.items.filter((item) => {
      if (options.category && item.category !== options.category) return false;
      if (roomFilter.size > 0 && !item.roomTags.some((tag) => roomFilter.has(tag))) return false;
      if (styleFilter.size > 0 && !item.styleTags.some((tag) => styleFilter.has(tag))) return false;
      if (materialFilter.size > 0 && !materialFilter.has(item.material.normalizedMaterial.toLowerCase())) return false;
      if (availabilityFilter.size > 0 && !availabilityFilter.has(item.availability)) return false;
      if (configurabilityFilter.size > 0 && (item.configurability == null || !configurabilityFilter.has(item.configurability))) return false;
      if (mountingFilter.size > 0 && !(item.mounting ?? ["floor"]).some((mounting) => mountingFilter.has(mounting))) return false;
      if (assetReadinessFilter.size > 0 && !(item.assetReadiness ?? ["ready"]).some((state) => assetReadinessFilter.has(state))) return false;
      // Dimension range filter
      if (dim) {
        const { widthMm, depthMm, heightMm } = item.dimensions;
        if (dim.minWidthMm != null && widthMm < dim.minWidthMm) return false;
        if (dim.maxWidthMm != null && widthMm > dim.maxWidthMm) return false;
        if (dim.minDepthMm != null && depthMm < dim.minDepthMm) return false;
        if (dim.maxDepthMm != null && depthMm > dim.maxDepthMm) return false;
        if (dim.minHeightMm != null && heightMm < dim.minHeightMm) return false;
        if (dim.maxHeightMm != null && heightMm > dim.maxHeightMm) return false;
      }
      return true;
    });
  }

  /**
   * Search with synonym expansion, ranking, and typo tolerance.
   */
  search(query: string, options: InventorySearchOptions = {}): InventorySearchResult {
    const { pageSize = 20, minScore = 1, typoTolerance = true } = options;
    const candidates = this.filterItems(options);

    if (!query || query.trim().length === 0) {
      return { items: candidates.slice(0, pageSize), totalCount: candidates.length, query: "", relaxed: false };
    }

    const queryLower = query.trim().toLowerCase();
    const queryTokens = tokenize(query);

    // Primary search — uses pre-tokenized cache to avoid per-item tokenize() calls.
    let scored = candidates
      .map((item) => ({
        item,
        score: scoreItem(item, this.itemTokenCache.get(item.id) ?? [], queryTokens, queryLower),
      }))
      .filter((s) => s.score >= minScore)
      .sort(compareScoredItems);

    // Typo tolerance for zero results
    let relaxed = false;
    let suggestedCorrection: string | undefined;

    if (scored.length === 0 && typoTolerance) {
      const typoVariants: string[] = [];
      for (const token of queryTokens) {
        typoVariants.push(...generateTypoVariants(token));
      }

      if (typoVariants.length > 0) {
        const typoTokens = tokenize(typoVariants.join(" "));
        scored = candidates
          .map((item) => ({
            item,
            score: scoreItem(item, this.itemTokenCache.get(item.id) ?? [], typoTokens, queryLower),
          }))
          .filter((s) => s.score >= 1)
          .sort(compareScoredItems);

        if (scored.length > 0) {
          relaxed = true;
          suggestedCorrection = typoVariants[0];
        }
      }
    }
    // compareScoredItems already provides deterministic tie-breaking via name/SKU/ID.

    return {
      items: scored.slice(0, pageSize).map((s) => s.item),
      totalCount: scored.length,
      query,
      relaxed,
      suggestedCorrection,
    };
  }

  /**
   * Auto-complete suggestions for a partial query.
   */
  suggest(query: string, limit = 5): string[] {
    if (!query || query.trim().length < 2) return [];
    const queryLower = query.trim().toLowerCase();
    const suggestions = new Set<string>();

    for (const item of this.items) {
      if (item.name.toLowerCase().includes(queryLower)) {
        suggestions.add(item.name);
      }
      for (const tag of item.tags) {
        if (tag.toLowerCase().includes(queryLower)) {
          suggestions.add(tag);
        }
      }
      if (suggestions.size >= limit) break;
    }

    return Array.from(suggestions).slice(0, limit);
  }
}

/**
 * Phase 03A Inventory State Contracts
 *
 * Inventory panel state, filters, sort, collections, collapsed/expanded state,
 * recent/frequent items, and command contracts for Phase 05 docking/UI integration.
 *
 * Defines the contract between the inventory data layer and the UI layer.
 * Phase 05 implements docking and final visuals using these contracts.
 */

import type {
  Open3dCatalogItem,
  Open3dCatalogCategory,
  Open3dRoomTag,
  Open3dStyleTag,
} from "../catalogTypes";
import type { InventorySortKey, InventoryDensity } from "./inventoryTaxonomy";

// ── Inventory panel state ──

export type InventoryMode = "browse" | "search";

export interface InventoryItemIdentity {
  itemId: string;
  variantId: string | null;
}

export interface InventoryLoadedRange {
  startIndex: number;
  endIndex: number;
  totalCount: number;
}

export type InventoryAnnouncementKind = "placement" | "filter-count" | "undo-redo" | "error";

export interface InventoryAnnouncement {
  kind: InventoryAnnouncementKind;
  message: string;
  politeness: "polite" | "assertive";
  createdAt: string;
}

export interface InventoryPanelState {
  /** Browse mode shows category/collection lanes; search mode shows query/facet results */
  mode: InventoryMode;
  /** Currently active search query text */
  searchQuery: string;
  /** Selected category filter ID (null = all) */
  selectedCategoryId: string | null;
  /** Selected subcategory filter ID (null = all) */
  selectedSubCategoryId: string | null;
  /** Selected room filter (null = all) */
  selectedRoomGroupId: string | null;
  /** Selected style filter (null = all) */
  selectedStyleGroupId: string | null;
  /** Active sort order */
  sortOrder: InventorySortKey;
  /** Display density */
  density: InventoryDensity;
  /** Collapsed/expanded state of each category (categoryId -> collapsed) */
  collapsedCategories: Record<string, boolean>;
  /** Whether the recent items panel is visible */
  recentVisible: boolean;
  /** Whether the favorites panel is visible */
  favoritesVisible: boolean;
  /** Focus retention is by catalog identity, not recycled DOM index */
  focusedItem: InventoryItemIdentity | null;
  /** Stable scroll restoration anchor for virtualized result lists */
  scrollAnchor: InventoryItemIdentity | null;
  /** Rendered virtualized range exposed for tests and screen-reader status */
  loadedRange: InventoryLoadedRange;
  /** Last coalesced announcement for placement/filter/error workflows */
  liveAnnouncement: InventoryAnnouncement | null;
}

/** Default inventory panel state */
export function defaultInventoryPanelState(): InventoryPanelState {
  return {
    mode: "browse",
    searchQuery: "",
    selectedCategoryId: null,
    selectedSubCategoryId: null,
    selectedRoomGroupId: null,
    selectedStyleGroupId: null,
    sortOrder: "name-asc",
    density: "comfortable",
    collapsedCategories: {},
    recentVisible: false,
    favoritesVisible: false,
    focusedItem: null,
    scrollAnchor: null,
    loadedRange: { startIndex: 0, endIndex: 0, totalCount: 0 },
    liveAnnouncement: null,
  };
}

// ── Inventory command contracts ──

/** Actions that the inventory panel dispatches */
export type InventoryCommand =
  | { type: "SET_MODE"; mode: InventoryMode }
  | { type: "SET_SEARCH_QUERY"; query: string }
  | { type: "SELECT_CATEGORY"; categoryId: string | null }
  | { type: "SELECT_SUBCATEGORY"; subCategoryId: string | null }
  | { type: "SELECT_ROOM"; roomGroupId: string | null }
  | { type: "SELECT_STYLE"; styleGroupId: string | null }
  | { type: "SET_SORT"; sort: InventorySortKey }
  | { type: "SET_DENSITY"; density: InventoryDensity }
  | { type: "SET_FOCUSED_ITEM"; item: InventoryItemIdentity | null }
  | { type: "SET_SCROLL_ANCHOR"; item: InventoryItemIdentity | null }
  | { type: "SET_LOADED_RANGE"; range: InventoryLoadedRange }
  | { type: "ANNOUNCE"; announcement: InventoryAnnouncement }
  | { type: "CLEAR_ANNOUNCEMENT" }
  | { type: "TOGGLE_CATEGORY_COLLAPSE"; categoryId: string }
  | { type: "TOGGLE_RECENT_VISIBLE" }
  | { type: "TOGGLE_FAVORITES_VISIBLE" }
  | { type: "PLACE_ITEM"; itemId: string; variantId: string | null; position: { x: number; y: number } }
  | { type: "ADD_TO_FAVORITES"; itemId: string }
  | { type: "REMOVE_FROM_FAVORITES"; itemId: string }
  | { type: "CLEAR_SEARCH" }
  | { type: "RESET_FILTERS" };

/** Result of processing an inventory command */
export interface InventoryCommandResult {
  /** Updated panel state */
  state: InventoryPanelState;
  /** Placed item (if placement command) */
  placedItem?: {
    itemId: string;
    variantId: string | null;
    position: { x: number; y: number };
  };
}

// ── Inventory command processor ──

/**
 * Pure reducer for inventory panel commands.
 * Phase 05 UI uses this to derive display state from commands.
 */
export function reduceInventoryCommand(
  state: InventoryPanelState,
  command: InventoryCommand,
): InventoryPanelState {
  switch (command.type) {
    case "SET_MODE":
      return { ...state, mode: command.mode };
    case "SET_SEARCH_QUERY":
      return { ...state, searchQuery: command.query, mode: command.query.trim() ? "search" : state.mode };
    case "SELECT_CATEGORY":
      return {
        ...state,
        selectedCategoryId: command.categoryId,
        selectedSubCategoryId: null,
      };
    case "SELECT_SUBCATEGORY":
      return { ...state, selectedSubCategoryId: command.subCategoryId };
    case "SELECT_ROOM":
      return { ...state, selectedRoomGroupId: command.roomGroupId };
    case "SELECT_STYLE":
      return { ...state, selectedStyleGroupId: command.styleGroupId };
    case "SET_SORT":
      return { ...state, sortOrder: command.sort };
    case "SET_DENSITY":
      return { ...state, density: command.density };
    case "SET_FOCUSED_ITEM":
      return { ...state, focusedItem: command.item };
    case "SET_SCROLL_ANCHOR":
      return { ...state, scrollAnchor: command.item };
    case "SET_LOADED_RANGE":
      return { ...state, loadedRange: command.range };
    case "ANNOUNCE":
      return { ...state, liveAnnouncement: command.announcement };
    case "CLEAR_ANNOUNCEMENT":
      return { ...state, liveAnnouncement: null };
    case "TOGGLE_CATEGORY_COLLAPSE":
      return {
        ...state,
        collapsedCategories: {
          ...state.collapsedCategories,
          [command.categoryId]: !state.collapsedCategories[command.categoryId],
        },
      };
    case "TOGGLE_RECENT_VISIBLE":
      return { ...state, recentVisible: !state.recentVisible };
    case "TOGGLE_FAVORITES_VISIBLE":
      return { ...state, favoritesVisible: !state.favoritesVisible };
    case "CLEAR_SEARCH":
      return { ...state, searchQuery: "", mode: "browse" };
    case "RESET_FILTERS":
      return defaultInventoryPanelState();
    default:
      return state;
  }
}

// ── Collections state ──

export interface InventoryCollectionsState {
  /** Recently placed items (most recent first, max 50) */
  recent: Array<{ itemId: string; variantId?: string; placedAt: string }>;
  /** Project-level recents stay separate from in-editor recently placed items */
  projectRecent: Array<{ itemId: string; variantId?: string; openedAt: string }>;
  /** Frequently used items with usage count */
  frequent: Array<{ itemId: string; variantId?: string; useCount: number }>;
  /** Favorited item IDs */
  favorites: string[];
  /** Custom user collections (project-specific groupings) */
  collections: Array<{ id: string; name: string; itemIds: string[] }>;
}

const MAX_RECENT_ITEMS = 50;

function stableUniqueItemIds(itemIds: string[]): string[] {
  return Array.from(new Set(itemIds)).sort((a, b) => a.localeCompare(b));
}

export function defaultCollectionsState(): InventoryCollectionsState {
  return {
    recent: [],
    projectRecent: [],
    frequent: [],
    favorites: [],
    collections: [],
  };
}

export function addInventoryRecent(
  state: InventoryCollectionsState,
  itemId: string,
  placedAt: string,
  variantId?: string | null,
): InventoryCollectionsState {
  const sameIdentity = (entry: { itemId: string; variantId?: string }) =>
    entry.itemId === itemId && (entry.variantId ?? null) === (variantId ?? null);
  const identityEntry = {
    itemId,
    ...(variantId ? { variantId } : {}),
  };
  const recent = [
    { ...identityEntry, placedAt },
    ...state.recent.filter((entry) => !sameIdentity(entry)),
  ].slice(0, MAX_RECENT_ITEMS);

  const useCount = (state.frequent.find((entry) => sameIdentity(entry))?.useCount ?? 0) + 1;
  const frequent = [
    ...state.frequent.filter((entry) => !sameIdentity(entry)),
    { ...identityEntry, useCount },
  ].sort((a, b) => (b.useCount - a.useCount) || a.itemId.localeCompare(b.itemId) || (a.variantId ?? "").localeCompare(b.variantId ?? ""));

  return { ...state, recent, frequent };
}

export function addProjectRecent(
  state: InventoryCollectionsState,
  itemId: string,
  openedAt: string,
  variantId?: string | null,
): InventoryCollectionsState {
  const sameIdentity = (entry: { itemId: string; variantId?: string }) =>
    entry.itemId === itemId && (entry.variantId ?? null) === (variantId ?? null);
  const entry = { itemId, ...(variantId ? { variantId } : {}), openedAt };
  return {
    ...state,
    projectRecent: [entry, ...state.projectRecent.filter((item) => !sameIdentity(item))].slice(0, MAX_RECENT_ITEMS),
  };
}

export function addInventoryFavorite(state: InventoryCollectionsState, itemId: string): InventoryCollectionsState {
  if (state.favorites.includes(itemId)) return state;
  return { ...state, favorites: stableUniqueItemIds([...state.favorites, itemId]) };
}

export function removeInventoryFavorite(state: InventoryCollectionsState, itemId: string): InventoryCollectionsState {
  return { ...state, favorites: state.favorites.filter((favoriteId) => favoriteId !== itemId) };
}

export function isInventoryFavorite(state: InventoryCollectionsState, itemId: string): boolean {
  return state.favorites.includes(itemId);
}

export function upsertInventoryCollection(
  state: InventoryCollectionsState,
  collection: { id: string; name: string; itemIds: string[] },
): InventoryCollectionsState {
  const normalized = { ...collection, itemIds: stableUniqueItemIds(collection.itemIds) };
  const collections = [
    ...state.collections.filter((entry) => entry.id !== collection.id),
    normalized,
  ].sort((a, b) => a.name.localeCompare(b.name) || a.id.localeCompare(b.id));

  return { ...state, collections };
}

export function addInventoryItemToCollection(
  state: InventoryCollectionsState,
  collectionId: string,
  itemId: string,
): InventoryCollectionsState {
  const collection = state.collections.find((entry) => entry.id === collectionId);
  if (!collection) return state;
  return upsertInventoryCollection(state, {
    ...collection,
    itemIds: [...collection.itemIds, itemId],
  });
}

export function removeInventoryItemFromCollection(
  state: InventoryCollectionsState,
  collectionId: string,
  itemId: string,
): InventoryCollectionsState {
  const collection = state.collections.find((entry) => entry.id === collectionId);
  if (!collection) return state;
  return upsertInventoryCollection(state, {
    ...collection,
    itemIds: collection.itemIds.filter((entryId) => entryId !== itemId),
  });
}

// ── Inventory panel contract for Phase 05 ──

/**
 * Contract that Phase 05 UI must implement.
 * Defines what the docking/workflow layer expects from the inventory panel.
 */
export interface InventoryPanelContract {
  /** Panel unique ID for docking system */
  panelId: string;
  /** Panel display name */
  title: string;
  /** Default dock position */
  defaultDock: "left" | "right" | "bottom";
