    category: "Furniture",
    name,
    dimensions: dims,
    shapes: [
      rectShape(0, 0, w, d, { rx: 3 }),
      rectShape(0, 0, backH, w),
      rectShape(4, 4, backH - 8, w - 8),
    ],
  };
}
registerSymbolGenerator("chairs", chairSymbol);
registerSymbolGenerator("seating", chairSymbol);

