// ── Symbol resolution ──

/**
 * Resolve the best symbol generator for a category/subcategory combination.
 * Falls back through increasingly generic keys.
 */
export function resolveSymbolGenerator(category: Open3dCatalogCategory, subCategory?: string): SvgSymbolGenerator {
  if (subCategory) {
    const subKey = subCategory.toLowerCase().replace(/\s+/g, "-");
    const catSubKey = `${category}-${subCategory}`.toLowerCase().replace(/\s+/g, "-");
    // Try subcategory standalone first (how generators are registered)
    const gen = symbolGenerators.get(subKey) ?? symbolGenerators.get(catSubKey);
    if (gen) return gen;
  }
  const catKey = category.toLowerCase().replace(/\s+/g, "-");
  return symbolGenerators.get(catKey) ?? symbolGenerators.get("default")!;
}

/** Generate a deterministic symbol definition */
export function generateSymbol(
  category: Open3dCatalogCategory,
  subCategory: string | undefined,
  dimensions: Open3dCatalogDimensions,
  name: string,
): SvgSymbolDefinition {
  const normalized = normalizeDimensions(dimensions);
  const definition = resolveSymbolGenerator(category, subCategory)(normalized, name);
  return { ...definition, dimensions: normalized, version: definition.version ?? SVG_SYMBOL_VERSION };
}

// ── SVG rendering ──

/**
 * Simple string hash for content-based cache keys.
 */
function hashString(str: string): string {
  let hash = 0;
  for (let i = 0; i < str.length; i++) {
    const char = str.charCodeAt(i);
    hash = ((hash << 5) - hash) + char;
    hash |= 0;
  }
  return Math.abs(hash).toString(36);
}

function stableShapeSignature(shape: SvgShapeCommand): string {
  const attrs = Object.entries(shape.attrs)
    .sort(([left], [right]) => left.localeCompare(right))
    .map(([key, value]) => `${key}:${String(value)}`)
    .join(",");
  return `${shape.shape}(${attrs})`;
}

function symbolDefinitionSignature(definition: SvgSymbolDefinition): string {
  return [
    definition.version,
    definition.symbolId,
    definition.category,
    definition.dimensions.widthMm,
    definition.dimensions.depthMm,
    definition.dimensions.heightMm,
    definition.shapes.map(stableShapeSignature).join("|"),
  ].join(":");
}

function createSvgRenderCacheKey(
  definition: SvgSymbolDefinition,
  theme: SvgThemeName,
  themeColors: SvgThemeColors,
  rotation: number | undefined,
  scale: number | undefined,
): string {
  const geometrySignature = hashString(symbolDefinitionSignature(definition));
  const metadataSignature = hashString(createRenderMetadataSignature(definition));
  return [
    SVG_RENDER_GENERATOR_VERSION,
    definition.version,
    geometrySignature,
    metadataSignature,
    theme,
    themeColors.mode,
    rotation ?? 0,
    scale ?? 1,
  ].join(":");
}

/**
 * Apply theme colors to a shape command's attributes.
 */
function themeShape(shape: SvgShapeCommand, theme: SvgThemeColors): string {
  const attrs: string[] = [];
  for (const [key, value] of Object.entries(shape.attrs)) {
    attrs.push(`${key}="${formatAttrValue(value)}"`);
  }
  attrs.push(`fill="${shape.shape === "line" ? "none" : formatCssValue(theme.fill)}"`);
  attrs.push(`stroke="${formatCssValue(theme.stroke)}"`);
  attrs.push(`stroke-width="${theme.strokeWidth}px"`);
  attrs.push(`opacity="${theme.opacity}"`);
  return `<${shape.shape} ${attrs.join(" ")} />`;
}

/**
 * Render a symbol definition to SVG markup.
 *
 * This is the canonical SVG render pipeline. All paths (preview, canvas,
 * export) go through this function with different themes.
 *
 * Performance target: <10ms per symbol.
 */
export function renderSvgSymbol(
  definition: SvgSymbolDefinition,
  theme: SvgThemeName = "light",
  rotation?: number,
  scale?: number,
): SvgRenderOutput {
  const colors = SVG_THEMES[theme] ?? SVG_THEMES.light;
  assertTrustedSymbolDefinition(definition);
  const normalized = normalizeDimensions(definition.dimensions);
  const w = normalized.widthMm;
  const d = normalized.depthMm;
  const viewBox = stableViewBox(normalized);

  // Build shape markup
  const shapeMarkup = definition.shapes.map((s) => themeShape(s, colors)).join("\n  ");

  // Build accessible title
  const escapedName = escapeXml(definition.name);
  const title = `<title>${escapedName}</title>`;

  // Optional label
  let labelMarkup = "";
  if (definition.label) {
    const cx = w / 2;
    const cy = d / 2;
    labelMarkup = `\n  <text x="${cx}" y="${cy}" dominant-baseline="middle" text-anchor="middle" font-size="${Math.min(w, d) * 0.3}px" fill="${formatCssValue(colors.textFill)}" opacity="${colors.opacity}">${escapeXml(definition.label)}</text>`;
  }

  // Build SVG
  const transformParts: string[] = [];
  const safeRotation = Number.isFinite(rotation) ? rotation : undefined;
  const safeScale = scale && Number.isFinite(scale) && scale > 0 ? scale : undefined;
  if (safeRotation) {
    const cx = w / 2;
    const cy = d / 2;
    transformParts.push(`rotate(${safeRotation} ${cx} ${cy})`);
  }
  if (safeScale && safeScale !== 1) {
    transformParts.push(`scale(${safeScale})`);
  }
  const transform = transformParts.length > 0 ? ` transform="${transformParts.join(" ")}"` : "";
  const svgColor = formatCssValue(colors.color);

  const svg = [
    `<?xml version="1.0" encoding="UTF-8"?>`,
    `<svg xmlns="http://www.w3.org/2000/svg" viewBox="${viewBox}" width="${formatMmAsExactCm(w)}cm" height="${formatMmAsExactCm(d)}cm"${transform} role="img" aria-label="${escapedName}" style="color:${svgColor}">`,
    `  ${title}`,
    `  <g>`,
    `    ${shapeMarkup}`,
    `${labelMarkup}`,
    `  </g>`,
    `</svg>`,
  ].join("\n");

  const normalizedDefinition = { ...definition, dimensions: normalized };
  const cacheKey = createSvgRenderCacheKey(normalizedDefinition, theme, colors, safeRotation, safeScale);
  const contentHash = hashString(cacheKey);
  const generatedAt = 0;

  return {
    svg,
    viewBox,
    widthMm: w,
    heightMm: d,
    theme,
    generatedAt,
    contentHash,
  };
}

// ── SVG cache ──

const svgCache = new Map<string, SvgRenderOutput>();

function touchSvgCacheEntry(cacheKey: string, output: SvgRenderOutput): SvgRenderOutput {
  if (svgCache.has(cacheKey)) {
    svgCache.delete(cacheKey);
  }
  svgCache.set(cacheKey, output);

  while (svgCache.size > MAX_SVG_CACHE_ENTRIES) {
    const oldestKey = svgCache.keys().next().value as string | undefined;
    if (oldestKey == null) break;
    svgCache.delete(oldestKey);
  }

  return output;
}

/**
 * Get a cached or freshly rendered SVG for a symbol.
 * Cache key includes symbol ID, theme, rotation, and scale.
 */
export function getCachedSvgSymbol(
  definition: SvgSymbolDefinition,
  theme: SvgThemeName = "light",
  rotation?: number,
  scale?: number,
): SvgRenderOutput {
  const normalized = normalizeDimensions(definition.dimensions);
  const safeRotation = Number.isFinite(rotation) ? rotation : undefined;
  const safeScale = scale && Number.isFinite(scale) && scale > 0 ? scale : undefined;
  const normalizedDefinition = { ...definition, dimensions: normalized };
  const colors = SVG_THEMES[theme] ?? SVG_THEMES.light;
  const cacheKey = createSvgRenderCacheKey(normalizedDefinition, theme, colors, safeRotation, safeScale);
  const cached = svgCache.get(cacheKey);
  if (cached) return touchSvgCacheEntry(cacheKey, cached);

  const output = renderSvgSymbol(normalizedDefinition, theme, safeRotation, safeScale);
  return touchSvgCacheEntry(cacheKey, output);
}

export function getSvgSymbolDimensionAgreement(definition: SvgSymbolDefinition): SvgSymbolDimensionAgreement {
  const normalized = normalizeDimensions(definition.dimensions);
  const footprint = { widthMm: normalized.widthMm, depthMm: normalized.depthMm };
  return {
    viewBox: stableViewBox(normalized),
    preview: footprint,
    canvas: footprint,
    export: footprint,
    agrees: true,
  };
}

/**
 * Clear the SVG render cache.
 * Call when switching version or theme definitions.
 */
export function clearSvgCache(): void {
  svgCache.clear();
}

/**
 * Phase 03 Unit Conversion
 *
 * Canonical millimetre conversion for the Open3D catalog system.
 * Handles the legacy naming debt: OOFPLWeb catalog stores dimensions as cm
 * in fields named `widthMm`/`heightMm` despite the misleading suffix.
 *
 * All internal geometry uses canonical millimetres.
 * Display values are derived via centralized converters based on user-selected unit.
 */

import type { Open3dCatalogDimensions } from "./catalogTypes";

// ── Conversion constants ──

const MM_PER_CM = 10;
const MM_PER_M = 1000;
const MM_PER_INCH = 25.4;

const CONFIGURATOR_HEIGHT_MM_THRESHOLD = 300;

// ── Core converters ──

/**
 * Convert legacy OOFPLWeb catalog fields (stored as cm despite "Mm" suffix)
 * to canonical millimetres.
 *
 * NAMING DEBT: The OOFPLWeb `widthMm` and `heightMm` fields actually contain
 * centimetre values. This converter corrects for that. The naming is preserved
 * in the bridge layer to avoid breaking existing API consumers.
 */
export function canonicalMmFromCatalogCm(value: number): number {
  return Math.max(1, Math.round(value * MM_PER_CM));
}

/**
 * Configurator payloads currently mix units:
 * - footprint L/D values are supplied in centimetres
 * - H / heightMm values are supplied in millimetres despite the mixed contract
 *
 * Some callers may already normalize height to centimetres before mapping. To
 * stay resilient without mutating upstream contracts, values above the practical
 * furniture-height threshold are treated as millimetres and converted to cm.
 */
export function configuratorHeightCmFromMixedUnit(
  value: number | undefined,
  fallbackCm = 75,
): number {
  if (!Number.isFinite(value) || value == null || value <= 0) {
    return fallbackCm;
  }

  if (value > CONFIGURATOR_HEIGHT_MM_THRESHOLD) {
    return value / MM_PER_CM;
  }

  return value;
}

/**
 * Build Open3dCatalogDimensions from legacy cm values.
 */
export function canonicalDimensionsFromCatalogCm(params: {
  widthCm: number;
  depthCm: number;
  heightCm?: number;
  seatHeightCm?: number;
  weightKg?: number;
}): Open3dCatalogDimensions {
  return {
    widthMm: canonicalMmFromCatalogCm(params.widthCm),
    depthMm: canonicalMmFromCatalogCm(params.depthCm),
    heightMm: canonicalMmFromCatalogCm(params.heightCm ?? 75),
    seatHeightMm: params.seatHeightCm != null ? canonicalMmFromCatalogCm(params.seatHeightCm) : undefined,
    weightKg: params.weightKg,
  };
}

/**
 * Convert canonical millimetres to display centimetres.
 */
export function displayCmFromCanonicalMm(mm: number): number {
  return Math.round(mm / MM_PER_CM);
}

/**
 * Convert canonical millimetres to display inches.
 */
export function displayInFromCanonicalMm(mm: number): number {
  return Math.round((mm / MM_PER_INCH) * 100) / 100;
}

/**
 * Convert canonical millimetres to display metres.
 */
export function displayMFromCanonicalMm(mm: number): number {
  return Math.round((mm / MM_PER_M) * 1000) / 1000;
}

/**
 * Convert canonical millimetres to feet-inches string.
 */
export function displayFtInFromCanonicalMm(mm: number): string {
  const totalInches = mm / MM_PER_INCH;
  const feet = Math.floor(totalInches / 12);
  const inches = Math.round(totalInches % 12);
  return `${feet}' ${inches}"`;
}

/**
 * Format dimensions for display in the user's preferred unit.
 */
export function displayDimensions(
  dimensions: Open3dCatalogDimensions,
  unit: "mm" | "cm" | "m" | "in" | "ft-in",
): string {
  const converters: Record<string, (v: number) => string> = {
    mm: (v) => `${Math.round(v)} mm`,
    cm: (v) => `${displayCmFromCanonicalMm(v)} cm`,
    m: (v) => `${displayMFromCanonicalMm(v)} m`,
    in: (v) => `${displayInFromCanonicalMm(v)} in`,
    "ft-in": displayFtInFromCanonicalMm,
  };

  const fmt = converters[unit] ?? ((v: number) => `${displayCmFromCanonicalMm(v)} cm`);
  const parts: string[] = [`${fmt(dimensions.widthMm)} × ${fmt(dimensions.depthMm)}`];
  if (dimensions.heightMm > 0) {
    parts.push(`× ${fmt(dimensions.heightMm)}`);
  }
  return parts.join(" ");
}

/**
 * Build an accessible name for a catalog item including dimensions.
 * Example: "Office Chair, 45 cm by 45 cm by 90 cm"
 */
export function buildAccessibleName(name: string, dimensions: Open3dCatalogDimensions): string {
  const w = displayCmFromCanonicalMm(dimensions.widthMm);
  const d = displayCmFromCanonicalMm(dimensions.depthMm);
  const h = displayCmFromCanonicalMm(dimensions.heightMm);
  return `${name}, ${w} cm by ${d} cm by ${h} cm`;
}

// ── Validation ──

/**
 * Validate that dimensions are positive and within reasonable bounds.
 */
export function validateDimensions(dimensions: Open3dCatalogDimensions): {
  valid: boolean;
  errors: string[];
} {
  const errors: string[] = [];
  if (!Number.isFinite(dimensions.widthMm) || dimensions.widthMm <= 0) {
    errors.push("widthMm must be a positive finite number");
  }
  if (!Number.isFinite(dimensions.depthMm) || dimensions.depthMm <= 0) {
    errors.push("depthMm must be a positive finite number");
  }
  if (!Number.isFinite(dimensions.heightMm) || dimensions.heightMm <= 0) {
    errors.push("heightMm must be a positive finite number");
  }
  if (dimensions.widthMm > 100000) {
    errors.push("widthMm exceeds maximum reasonable value (100000 mm)");
  }
  if (dimensions.depthMm > 100000) {
    errors.push("depthMm exceeds maximum reasonable value (100000 mm)");
  }
  if (dimensions.heightMm > 100000) {
    errors.push("heightMm exceeds maximum reasonable value (100000 mm)");
  }
  if (dimensions.weightKg != null && (!Number.isFinite(dimensions.weightKg) || dimensions.weightKg < 0)) {
    errors.push("weightKg must be a non-negative finite number");
  }
  return { valid: errors.length === 0, errors };
}

