"use client";

import { useCallback, useEffect, useState, type Dispatch, type SetStateAction } from "react";

export type PanelId = "left" | "right" | "bottom";
export type PanelState = "docked" | "floating" | "collapsed";
export type ViewportTier = "desktop" | "tablet" | "small";

interface PanelConfig {
  id: PanelId;
  state: PanelState;
  width: number;
  height: number;
  x: number;
  y: number;
  zIndex: number;
}

interface DockingSystemState {
  panels: Record<PanelId, PanelConfig>;
  activePanel: PanelId | null;
  focusedPanel: PanelId | null;
  viewportTier: ViewportTier;
}

interface DockingSystemActions {
  dock: (panelId: PanelId) => void;
  undock: (panelId: PanelId) => void;
  toggleCollapse: (panelId: PanelId) => void;
  move: (panelId: PanelId, x: number, y: number) => void;
  resize: (panelId: PanelId, width: number, height: number) => void;
  reset: () => void;
  saveLayout: () => void;
  restoreLayout: () => void;
  setActivePanel: Dispatch<SetStateAction<PanelId | null>>;
  setFocusedPanel: Dispatch<SetStateAction<PanelId | null>>;
}

const STORAGE_KEY = "open3d-workspace-docking";

const DEFAULT_PANEL_CONFIG: Record<PanelId, PanelConfig> = {
  left: {
    id: "left",
    state: "docked",
    width: 310,
    height: 0, // 0 means fill remaining height
    x: 0,
    y: 0,
    zIndex: 55,
  },
  right: {
    id: "right",
    state: "docked",
    width: 290,
    height: 0,
    x: 0,
    y: 0,
    zIndex: 55,
  },
  bottom: {
    id: "bottom",
    state: "collapsed",
    width: 0,
    height: 200,
    x: 0,
    y: 0,
    zIndex: 55,
  },
};

function getViewportTier(): ViewportTier {
  if (typeof window === "undefined") return "desktop";
  if (window.innerWidth < 768) return "small";
  if (window.innerWidth < 1280) return "tablet";
  return "desktop";
}

function clamp(value: number, min: number, max: number): number {
  return Math.min(Math.max(value, min), max);
}

export function useDockingSystem(): DockingSystemState & DockingSystemActions {
  const [panels, setPanels] = useState<Record<PanelId, PanelConfig>>(DEFAULT_PANEL_CONFIG);
  const [activePanel, setActivePanel] = useState<PanelId | null>(null);
  const [focusedPanel, setFocusedPanel] = useState<PanelId | null>(null);
  const [viewportTier, setViewportTier] = useState<ViewportTier>(getViewportTier);

  // Handle viewport resize
  useEffect(() => {
    const handleResize = () => {
      const newTier = getViewportTier();
      setViewportTier((current) => {
        if (current !== newTier) {
          return newTier;
        }
        return current;
      });
    };

    window.addEventListener("resize", handleResize);
    return () => window.removeEventListener("resize", handleResize);
  }, []);

  // Load persisted layout on mount
  useEffect(() => {
    try {
      const stored = localStorage.getItem(STORAGE_KEY);
      if (stored) {
        const parsed = JSON.parse(stored) as Partial<Record<PanelId, PanelConfig>>;
        const restored = { ...DEFAULT_PANEL_CONFIG };
        let hasChanges = false;

        for (const id of Object.keys(parsed) as PanelId[]) {
          if (parsed[id] && DEFAULT_PANEL_CONFIG[id]) {
            // Don't restore collapsed state by default, keep docked
            if (parsed[id]!.state !== "collapsed") {
              restored[id] = { ...DEFAULT_PANEL_CONFIG[id], ...parsed[id] };
              hasChanges = true;
            }
          }
        }

        if (hasChanges) {
          setPanels(restored);
        }
      }
    } catch {
      // Ignore storage errors
    }
  }, []);

  const dock = useCallback((panelId: PanelId) => {
    setPanels((current) => ({
      ...current,
      [panelId]: {
        ...current[panelId],
        state: "docked",
        x: 0,
        y: 0,
      },
    }));
  }, []);

  const undock = useCallback((panelId: PanelId) => {
    const defaultWidth = panelId === "left" ? 310 : panelId === "right" ? 290 : 400;
    const defaultHeight = panelId === "bottom" ? 200 : 400;

    setPanels((current) => ({
      ...current,
      [panelId]: {
        ...current[panelId],
        state: "floating",
        width: current[panelId].state === "docked" ? defaultWidth : current[panelId].width,
        height: current[panelId].state === "docked" ? defaultHeight : current[panelId].height,
        x: viewportTier === "small" ? 20 : 100,
        y: viewportTier === "small" ? 80 : 100,
        zIndex: 100,
      },
    }));
  }, [viewportTier]);

  const toggleCollapse = useCallback((panelId: PanelId) => {
    setPanels((current) => ({
      ...current,
      [panelId]: {
        ...current[panelId],
        state: current[panelId].state === "collapsed" ? "docked" : "collapsed",
      },
    }));
  }, []);

  const move = useCallback(
    (panelId: PanelId, x: number, y: number) => {
      setPanels((current) => {
        const panel = current[panelId];
        const maxX = window.innerWidth - panel.width - 20;
        const maxY = window.innerHeight - 120; // Account for topbar

        return {
          ...current,
          [panelId]: {
            ...panel,
            x: clamp(x, 20, maxX),
            y: clamp(y, 60, maxY),
          },
        };
      });
    },
    [],
  );

  const resize = useCallback(
    (panelId: PanelId, width: number, height: number) => {
      const minWidth = 200;
      const minHeight = 150;
      const maxWidth = window.innerWidth - 40;
      const maxHeight = window.innerHeight - 120;

      setPanels((current) => ({
        ...current,
        [panelId]: {
          ...current[panelId],
          width: clamp(width, minWidth, maxWidth),
          height: clamp(height, minHeight, maxHeight),
        },
      }));
    },
    [],
  );

  const reset = useCallback(() => {
    setPanels(DEFAULT_PANEL_CONFIG);
    try {
      localStorage.removeItem(STORAGE_KEY);
    } catch {
      // Ignore storage errors
    }
  }, []);

  const saveLayout = useCallback(() => {
    try {
      const toSave: Record<PanelId, PanelConfig> = {} as Record<PanelId, PanelConfig>;
      for (const id of Object.keys(panels) as PanelId[]) {
        // Only save non-collapsed state
        if (panels[id].state !== "collapsed") {
          toSave[id] = panels[id];
        }
      }
      localStorage.setItem(STORAGE_KEY, JSON.stringify(toSave));
    } catch {
      // Ignore storage errors
    }
  }, [panels]);

  const restoreLayout = useCallback(() => {
    try {
      const stored = localStorage.getItem(STORAGE_KEY);
      if (stored) {
        const parsed = JSON.parse(stored) as Partial<Record<PanelId, PanelConfig>>;
        const restored = { ...DEFAULT_PANEL_CONFIG };

        for (const id of Object.keys(parsed) as PanelId[]) {
          if (parsed[id] && DEFAULT_PANEL_CONFIG[id]) {
            if (parsed[id]!.state !== "collapsed") {
              restored[id] = { ...DEFAULT_PANEL_CONFIG[id], ...parsed[id] };
            }
          }
        }

        setPanels(restored);
      }
    } catch {
      // Ignore storage errors
    }
  }, []);

  return {
    panels,
    activePanel,
    focusedPanel,
    viewportTier,
    dock,
    undock,
    toggleCollapse,
    move,
    resize,
    reset,
    saveLayout,
    restoreLayout,
    setActivePanel,
    setFocusedPanel,
  };
}

"use client";

import { useCallback, useState, type MouseEvent } from "react";
import type { Open3dDoor, Open3dProject, Open3dPoint, Open3dWall, Open3dWindow } from "../model/types";
import { addDoor, addWindow, removeDoor, removeWindow, updateDoor, updateWindow } from "../model/operations/pureActions";

export type DoorType = Open3dDoor["type"];
export type WindowType = Open3dWindow["type"];

export type PlacementMode = 
  | { mode: "select" }
  | { mode: "place-door"; doorType: DoorType }
  | { mode: "place-window"; windowType: WindowType }
  | { mode: "edit-door"; doorId: string }
  | { mode: "edit-window"; windowId: string };

export interface DoorWindowPlacementResult {
  /** The wall ID where the door/window was placed */
  wallId: string;
  /** Position along the wall (0-1 normalized) */
  position: number;
  /** Type of opening */
  type: DoorType | WindowType;
}

/**
 * Door/Window placement hook for the workspace canvas.
 * Provides state management and actions for placing and editing doors and windows on walls.
 */
export function useDoorWindowPlacement(project: Open3dProject | null) {
  const [placementMode, setPlacementMode] = useState<PlacementMode>({ mode: "select" });
  const [selectedWallId, setSelectedWallId] = useState<string | null>(null);
  const [hoverPosition, setHoverPosition] = useState<number | null>(null);

  // Door types available for placement
  const doorTypes: DoorType[] = ["single", "double", "sliding", "pocket", "french"];

  // Window types available for placement
  const windowTypes: WindowType[] = ["standard", "fixed", "casement", "sliding", "bay"];

  // Start door placement mode
  const startDoorPlacement = useCallback((doorType: DoorType = "single") => {
    setPlacementMode({ mode: "place-door", doorType });
  }, []);

  // Start window placement mode
  const startWindowPlacement = useCallback((windowType: WindowType = "standard") => {
    setPlacementMode({ mode: "place-window", windowType });
  }, []);

  // Cancel placement mode
  const cancelPlacement = useCallback(() => {
    setPlacementMode({ mode: "select" });
    setSelectedWallId(null);
    setHoverPosition(null);
  }, []);

  // Handle wall click during placement mode
  const handleWallClick = useCallback(
    (wallId: string, clickPosition: number): DoorWindowPlacementResult | null => {
      if (!project) return null;

      if (placementMode.mode === "place-door") {
        const result = addDoor(project, wallId, clickPosition, placementMode.doorType);
        // The caller should use result.project to update the project
        return { wallId, position: clickPosition, type: placementMode.doorType };
      }

      if (placementMode.mode === "place-window") {
        const result = addWindow(project, wallId, clickPosition, placementMode.windowType);
        return { wallId, position: clickPosition, type: placementMode.windowType };
      }

      return null;
    },
    [project, placementMode],
  );

  // Update hover position when moving over walls
  const handleWallHover = useCallback((wallId: string | null, position: number | null) => {
    setSelectedWallId(wallId);
    setHoverPosition(position);
  }, []);

  // Edit an existing door
  const editDoor = useCallback((doorId: string) => {
    setPlacementMode({ mode: "edit-door", doorId });
  }, []);

  // Edit an existing window
  const editWindow = useCallback((windowId: string) => {
    setPlacementMode({ mode: "edit-window", windowId });
  }, []);

  // Update door properties
  const updateDoorProperties = useCallback(
    (updatedProject: Open3dProject, doorId: string, updates: Partial<Open3dDoor>): Open3dProject => {
      return updateDoor(updatedProject, doorId, updates).project;
    },
    [],
  );

  // Update window properties
  const updateWindowProperties = useCallback(
    (updatedProject: Open3dProject, windowId: string, updates: Partial<Open3dWindow>): Open3dProject => {
      return updateWindow(updatedProject, windowId, updates).project;
    },
    [],
  );

  // Delete a door
  const deleteDoor = useCallback(
    (updatedProject: Open3dProject, doorId: string): Open3dProject => {
      return removeDoor(updatedProject, doorId).project;
    },
    [],
  );

  // Delete a window
  const deleteWindow = useCallback(
    (updatedProject: Open3dProject, windowId: string): Open3dProject => {
      return removeWindow(updatedProject, windowId).project;
    },
    [],
  );

  // Get doors on a specific wall
  const getDoorsOnWall = useCallback(
    (wallId: string): Open3dDoor[] => {
      if (!project) return [];
      const floor = project.floors.find((f) => f.id === project.activeFloorId);
      return floor?.doors.filter((d) => d.wallId === wallId) ?? [];
    },
    [project],
  );

  // Get windows on a specific wall
  const getWindowsOnWall = useCallback(
    (wallId: string): Open3dWindow[] => {
      if (!project) return [];
      const floor = project.floors.find((f) => f.id === project.activeFloorId);
      return floor?.windows.filter((w) => w.wallId === wallId) ?? [];
    },
    [project],
  );

  // Check if currently in placement mode
  const isPlacing = placementMode.mode === "place-door" || placementMode.mode === "place-window";
  const isEditing = placementMode.mode === "edit-door" || placementMode.mode === "edit-window";

  return {
    // State
    placementMode,
    selectedWallId,
    hoverPosition,
    isPlacing,
    isEditing,

    // Available types
    doorTypes,
    windowTypes,

    // Actions
    startDoorPlacement,
    startWindowPlacement,
    cancelPlacement,
    handleWallClick,
    handleWallHover,
    editDoor,
    editWindow,
    updateDoorProperties,
    updateWindowProperties,
    deleteDoor,
    deleteWindow,
    getDoorsOnWall,
    getWindowsOnWall,
  };
}

"use client";

import { useCallback, useState } from "react";
import type {
  Open3dAnnotation,
  Open3dColumn,
  Open3dGuide,
  Open3dMeasurement,
  Open3dPoint,
  Open3dProject,
  Open3dRoom,
  Open3dStair,
  Open3dTextAnnotation,
} from "../model/types";
import {
  addStair,
  addColumn,
  addMeasurement,
  addAnnotation,
  addGuide,
  updateRoom,
  removeStair,
  removeColumn,
  removeMeasurement,
  removeAnnotation,
  removeGuide,
} from "../model/operations/pureActions";

export type RoomElementMode =
  | { mode: "select" }
  | { mode: "place-stair" }
  | { mode: "place-column" }
  | { mode: "place-measurement" }
  | { mode: "place-annotation" }
  | { mode: "place-guide" }
  | { mode: "place-text" }
  | { mode: "edit-room"; roomId: string };

/**
 * Room elements hook for the workspace canvas.
 * Provides state management and actions for rooms, labels, measurements,
 * annotations, stairs, columns, guides, and layers.
 */
export function useRoomElements(project: Open3dProject | null) {
  const [elementMode, setElementMode] = useState<RoomElementMode>({ mode: "select" });
  const [selectedElementId, setSelectedElementId] = useState<string | null>(null);

  // Room categories
  const roomCategories: Open3dRoom["roomType"][] = ["indoor", "outdoor", "garage", "utility"];

  // Stair types
  const stairTypes = ["straight", "l-shaped", "u-shaped", "spiral"] as const;

  // Column shapes
  const columnShapes = ["square", "round", "rectangular"] as const;

  // Guide types
  const guideTypes = ["horizontal", "vertical", "angle"] as const;

  // ─── Room actions ───

  // Start room editing mode
  const startRoomEdit = useCallback((roomId: string) => {
    setElementMode({ mode: "edit-room", roomId });
    setSelectedElementId(roomId);
  }, []);

  // Update room properties
  const updateRoomProperties = useCallback(
    (updatedProject: Open3dProject, roomId: string, updates: Partial<Open3dRoom>): Open3dProject => {
      return updateRoom(updatedProject, roomId, updates).project;
    },
    [],
  );

  // Delete room - manually filter since no removeRoom action exists
  const deleteRoom = useCallback(
    (updatedProject: Open3dProject, roomId: string): Open3dProject => {
      const p = { ...updatedProject };
      const floorIndex = p.floors.findIndex((f) => f.id === p.activeFloorId);
      if (floorIndex >= 0) {
        p.floors = [...p.floors];
        p.floors[floorIndex] = {
          ...p.floors[floorIndex],
          rooms: p.floors[floorIndex].rooms.filter((r) => r.id !== roomId),
        };
      }
      return p;
    },
    [],
  );

  // Get room by ID
  const getRoomById = useCallback(
    (roomId: string): Open3dRoom | undefined => {
      if (!project) return undefined;
      const floor = project.floors.find((f) => f.id === project.activeFloorId);
      return floor?.rooms.find((r) => r.id === roomId);
    },
    [project],
  );

  // Get all rooms
  const getAllRooms = useCallback((): Open3dRoom[] => {
    if (!project) return [];
    const floor = project.floors.find((f) => f.id === project.activeFloorId);
    return floor?.rooms ?? [];
  }, [project]);

  // Calculate room area
  const calculateRoomArea = useCallback((room: Open3dRoom): number => {
    return room.area ?? 0;
  }, []);

  // ─── Stair actions ───

  const startStairPlacement = useCallback(() => {
    setElementMode({ mode: "place-stair" });
  }, []);

  const placeStair = useCallback(
    (updatedProject: Open3dProject, position: Open3dPoint): Open3dProject => {
      return addStair(updatedProject, position).project;
    },
    [],
  );

  const deleteStair = useCallback(
    (updatedProject: Open3dProject, stairId: string): Open3dProject => {
      return removeStair(updatedProject, stairId).project;
    },
    [],
  );

  // Get all stairs
  const getAllStairs = useCallback((): Open3dStair[] => {
    if (!project) return [];
    const floor = project.floors.find((f) => f.id === project.activeFloorId);
    return floor?.stairs ?? [];
  }, [project]);

  // ─── Column actions ───

  const startColumnPlacement = useCallback(() => {
    setElementMode({ mode: "place-column" });
  }, []);

  const placeColumn = useCallback(
    (updatedProject: Open3dProject, position: Open3dPoint, shape: "square" | "round" = "square"): Open3dProject => {
      return addColumn(updatedProject, position, shape).project;
    },
    [],
  );

  const deleteColumn = useCallback(
    (updatedProject: Open3dProject, columnId: string): Open3dProject => {
      return removeColumn(updatedProject, columnId).project;
    },
    [],
  );

  // Get all columns
  const getAllColumns = useCallback((): Open3dColumn[] => {
    if (!project) return [];
    const floor = project.floors.find((f) => f.id === project.activeFloorId);
    return floor?.columns ?? [];
  }, [project]);

  // ─── Measurement actions ───

  const startMeasurementPlacement = useCallback(() => {
    setElementMode({ mode: "place-measurement" });
  }, []);

  const placeMeasurement = useCallback(
    (updatedProject: Open3dProject, x1: number, y1: number, x2: number, y2: number): Open3dProject => {
      return addMeasurement(updatedProject, x1, y1, x2, y2).project;
    },
    [],
  );

  const deleteMeasurement = useCallback(
    (updatedProject: Open3dProject, measurementId: string): Open3dProject => {
      return removeMeasurement(updatedProject, measurementId).project;
    },
    [],
  );

  // Get all measurements
  const getAllMeasurements = useCallback((): Open3dMeasurement[] => {
    if (!project) return [];
    const floor = project.floors.find((f) => f.id === project.activeFloorId);
    return floor?.measurements ?? [];
  }, [project]);

  // ─── Annotation actions ───

  const startAnnotationPlacement = useCallback(() => {
    setElementMode({ mode: "place-annotation" });
  }, []);

  const startTextAnnotation = useCallback(() => {
    setElementMode({ mode: "place-text" });
  }, []);

  const placeAnnotation = useCallback(
    (updatedProject: Open3dProject, x1: number, y1: number, x2: number, y2: number, label?: string): Open3dProject => {
      return addAnnotation(updatedProject, x1, y1, x2, y2, 400, label).project;
    },
    [],
  );

  const deleteAnnotation = useCallback(
    (updatedProject: Open3dProject, annotationId: string): Open3dProject => {
      return removeAnnotation(updatedProject, annotationId).project;
    },
    [],
  );

  // Get all annotations
  const getAllAnnotations = useCallback((): Open3dAnnotation[] => {
    if (!project) return [];
    const floor = project.floors.find((f) => f.id === project.activeFloorId);
    return floor?.annotations ?? [];
  }, [project]);

  // ─── Guide actions ───

  const startGuidePlacement = useCallback(() => {
    setElementMode({ mode: "place-guide" });
  }, []);

  const placeGuide = useCallback(
    (updatedProject: Open3dProject, position: number, orientation: "horizontal" | "vertical" = "horizontal"): Open3dProject => {
      return addGuide(updatedProject, orientation, position).project;
    },
    [],
  );

  const deleteGuide = useCallback(
    (updatedProject: Open3dProject, guideId: string): Open3dProject => {
      return removeGuide(updatedProject, guideId).project;
    },
    [],
  );

  // Get all guides
  const getAllGuides = useCallback((): Open3dGuide[] => {
    if (!project) return [];
    const floor = project.floors.find((f) => f.id === project.activeFloorId);
    return floor?.guides ?? [];
  }, [project]);

  // ─── Selection ───

  const selectElement = useCallback((elementId: string | null) => {
    setSelectedElementId(elementId);
  }, []);

  // ─── Mode exit ───

  const cancelMode = useCallback(() => {
    setElementMode({ mode: "select" });
    setSelectedElementId(null);
  }, []);

  // Check if in placement mode
  const isPlacing =
    elementMode.mode !== "select" && elementMode.mode !== "edit-room";
  const isEditing = elementMode.mode === "edit-room";

  return {
    // State
    elementMode,
    selectedElementId,
    isPlacing,
    isEditing,

    // Options
    roomCategories,
    stairTypes,
    columnShapes,
    guideTypes,

    // Room actions
    startRoomEdit,
    updateRoomProperties,
    deleteRoom,
