"use client";

import { useCallback, useMemo, useState } from "react";
import type { Open3dProject, Open3dPoint, Open3dWall, Open3dFloor } from "../model/types";
import { readThemeColor } from "../shared/readThemeColor";
import {
  createOpen3dHistory,
  dispatchOpen3dAction,
  undoOpen3dAction,
  redoOpen3dAction,
  type Open3dHistoryState,
} from "../store/history";
import { createOpen3dProject } from "../model/project";
import type { Open3dProjectAction } from "../model/actions/projectActions";

export interface CanvasSelection {
  type: "wall" | "door" | "window" | "furniture" | "room" | "none";
  ids: string[];
}

export interface WorkspaceCanvasContext {
  /** Current project state */
  project: Open3dProject;
  /** Active floor from project */
  activeFloor: Open3dFloor;
  /** History state for undo/redo */
  history: Open3dHistoryState;
  /** Current selection */
  selection: CanvasSelection;
  /** Whether undo is available */
  canUndo: boolean;
  /** Whether redo is available */
  canRedo: boolean;
  /** Dispatch an action to modify the project */
  dispatch: (action: Open3dProjectAction) => void;
  /** Undo the last action */
  undo: () => void;
  /** Redo the last undone action */
  redo: () => void;
  /** Set selection */
  setSelection: (selection: CanvasSelection) => void;
  /** Update project directly (for canvas interactions) */
  updateProject: (updater: (project: Open3dProject) => Open3dProject) => void;
  /** Replace document and reset history (restore/autosave load) */
  replaceProject: (project: Open3dProject) => void;
}

export interface UseWorkspaceCanvasOptions {
  /** Initial project name */
  projectName?: string;
  /** Initial project (if provided, takes precedence over projectName) */
  initialProject?: Open3dProject;
  /** Maximum history entries */
  maxHistory?: number;
}

const DEFAULT_PROJECT_NAME = "Untitled Project";

export function useWorkspaceCanvas(
  options: UseWorkspaceCanvasOptions = {},
): WorkspaceCanvasContext {
  const { projectName = DEFAULT_PROJECT_NAME, initialProject } = options;

  // Create initial project if not provided
  const initialProjectState = useMemo(() => {
    if (initialProject) {
      return initialProject;
    }
    return createOpen3dProject({ name: projectName });
  }, [initialProject, projectName]);

  // Project state
  const [project, setProject] = useState<Open3dProject>(initialProjectState);

  // History state
  const [history, setHistory] = useState<Open3dHistoryState>(() =>
    createOpen3dHistory(initialProjectState),
  );

  // Selection state
  const [selection, setSelection] = useState<CanvasSelection>({ type: "none", ids: [] });

  // Get active floor
  const activeFloor = useMemo(() => {
    return (
      project.floors.find((floor) => floor.id === project.activeFloorId) ??
      project.floors[0]
    );
  }, [project, project.activeFloorId]);

  // Can undo/redo
  const canUndo = history.past.length > 0;
  const canRedo = history.future.length > 0;

  // Dispatch action - updates project and history
  const dispatch = useCallback(
    (action: Open3dProjectAction) => {
      const nextHistory = dispatchOpen3dAction(history, action);
      if (nextHistory !== history) {
        setHistory(nextHistory);
        setProject(nextHistory.present);
      }
    },
    [history],
  );

  // Undo action
  const undo = useCallback(() => {
    const nextHistory = undoOpen3dAction(history);
    if (nextHistory !== history) {
      setHistory(nextHistory);
      setProject(nextHistory.present);
    }
  }, [history]);

  // Redo action
  const redo = useCallback(() => {
    const nextHistory = redoOpen3dAction(history);
    if (nextHistory !== history) {
      setHistory(nextHistory);
      setProject(nextHistory.present);
    }
  }, [history]);

  // Update project directly (for canvas interactions like drawing walls)
  const updateProject = useCallback(
    (updater: (project: Open3dProject) => Open3dProject) => {
      setProject((current) => {
        const updated = updater(current);
        if (updated === current) return current;
        const stamped =
          updated.updatedAt === current.updatedAt
            ? { ...updated, updatedAt: new Date().toISOString() }
            : updated;
        setHistory((h) => ({
          past: [...h.past, h.present],
          present: stamped,
          future: [],
          dragStart: null,
        }));
        return stamped;
      });
    },
    [],
  );

  const replaceProject = useCallback((next: Open3dProject) => {
    setProject(next);
    setHistory(createOpen3dHistory(next));
    setSelection({ type: "none", ids: [] });
  }, []);

  return {
    project,
    activeFloor,
    history,
    selection,
    canUndo,
    canRedo,
    dispatch,
    undo,
    redo,
    setSelection,
    updateProject,
    replaceProject,
  };
}

/**
 * Hook for canvas that needs wall drawing capabilities.
 * This combines the workspace canvas context with canvas-specific state.
 */
export function useCanvasDrawing(initialProject?: Open3dProject) {
  const canvas = useWorkspaceCanvas({
    initialProject,
    projectName: initialProject?.name ?? "Feasibility project",
  });

  // Drawing-specific state
  const [drawingPoint, setDrawingPoint] = useState<{
    start: Open3dPoint;
    current: Open3dPoint;
  } | null>(null);

  // Add a wall to the project
  const addWall = useCallback(
    (start: Open3dPoint, end: Open3dPoint) => {
      canvas.updateProject((project) => {
        const floor = project.floors[0];
        const newWall: Open3dWall = {
          id: crypto.randomUUID(),
          start,
          end,
          thickness: 150, // default 150mm
          height: 2400, // default 2400mm
          color: readThemeColor("--text-body"),
        };
        return {
          ...project,
          floors: project.floors.map((f) =>
            f.id === floor.id
              ? { ...f, walls: [...f.walls, newWall] }
              : f,
          ),
        };
      });
    },
    [canvas],
  );

  // Start drawing a wall
  const startDrawing = useCallback((point: Open3dPoint) => {
    setDrawingPoint({ start: point, current: point });
  }, []);

  // Update drawing preview
  const updateDrawing = useCallback((point: Open3dPoint) => {
    setDrawingPoint((prev) => (prev ? { ...prev, current: point } : null));
  }, []);

  // Commit the drawing
  const commitDrawing = useCallback(() => {
    if (drawingPoint) {
      const dx = drawingPoint.current.x - drawingPoint.start.x;
      const dy = drawingPoint.current.y - drawingPoint.start.y;
      const length = Math.hypot(dx, dy);
      if (length > 10) {
        // Minimum 10mm to create a wall
        addWall(drawingPoint.start, drawingPoint.current);
      }
      setDrawingPoint(null);
    }
  }, [drawingPoint, addWall]);

  // Cancel drawing
  const cancelDrawing = useCallback(() => {
    setDrawingPoint(null);
  }, []);

  return {
    ...canvas,
    drawingPoint,
    startDrawing,
    updateDrawing,
    commitDrawing,
    cancelDrawing,
  };
}

import type { CanvasTool } from "../../editor/canvasTool";
import { CANVAS_TOOL_LABELS, CANVAS_TOOL_SHORTCUTS } from "../../editor/canvasTool";
import { feasibilityCommands } from "./registry";

export type PaletteCommandCategory = "tool" | "action" | "navigation";

export interface PaletteCommand {
  id: string;
  label: string;
  shortcut?: string;
  category: PaletteCommandCategory;
  categoryLabel: string;
  keywords?: string[];
}

export interface PaletteCommandHandlers {
  setTool: (tool: CanvasTool) => void;
  toggleView: () => void;
  openPalette: () => void;
  undo: () => void;
  redo: () => void;
  cancel: () => void;
  zoomReset: () => void;
}

const TOOL_IDS: CanvasTool[] = ["select", "wall", "door", "window", "text", "pan"];

export function buildPaletteCommands(handlers: PaletteCommandHandlers): PaletteCommand[] {
  const toolCommands: PaletteCommand[] = TOOL_IDS.map((tool) => ({
    id: `tool-${tool}`,
    label: `${CANVAS_TOOL_LABELS[tool]} tool`,
    shortcut: CANVAS_TOOL_SHORTCUTS[tool],
    category: "tool",
    categoryLabel: "Tools",
    keywords: [tool, CANVAS_TOOL_LABELS[tool].toLowerCase()],
  }));

  const actionCommands: PaletteCommand[] = feasibilityCommands.map((command) => ({
    id: `action-${command.id}`,
    label: command.label,
    shortcut: command.shortcut,
    category: "action",
    categoryLabel: "Actions",
    keywords: [command.id],
  }));

  const navigationCommands: PaletteCommand[] = [
    {
      id: "nav-toggle-view",
      label: "Toggle 2D / 3D view",
      shortcut: "Tab",
      category: "navigation",
      categoryLabel: "View",
      keywords: ["2d", "3d", "view", "toggle"],
    },
    {
      id: "nav-open-palette",
      label: "Open command palette",
      shortcut: "Ctrl+K",
      category: "navigation",
      categoryLabel: "View",
      keywords: ["search", "commands", "palette"],
    },
    {
      id: "nav-redo",
      label: "Redo",
      shortcut: "Ctrl+Shift+Z",
      category: "action",
      categoryLabel: "Actions",
      keywords: ["redo"],
    },
  ];

  return [...navigationCommands, ...actionCommands, ...toolCommands];
}

export function filterPaletteCommands(
  commands: readonly PaletteCommand[],
  query: string,
  limit = 20,
): PaletteCommand[] {
  const normalized = query.trim().toLowerCase();
  if (!normalized) return commands.slice(0, 12);
  return commands
    .filter((command) => {
      const haystack = [
        command.label,
        command.categoryLabel,
        command.shortcut ?? "",
        ...(command.keywords ?? []),
      ]
        .join(" ")
        .toLowerCase();
      return haystack.includes(normalized);
    })
    .slice(0, limit);
}

export function runPaletteCommand(
  id: string,
  handlers: PaletteCommandHandlers,
): boolean {
  if (id.startsWith("tool-")) {
    const tool = id.slice("tool-".length) as CanvasTool;
    handlers.setTool(tool);
    return true;
  }

  switch (id) {
    case "nav-toggle-view":
      handlers.toggleView();
      return true;
    case "nav-open-palette":
      handlers.openPalette();
      return true;
    case "nav-redo":
      handlers.redo();
      return true;
    case "action-draw-wall":
      handlers.setTool("wall");
      return true;
    case "action-cancel":
      handlers.cancel();
      return true;
    case "action-undo":
      handlers.undo();
      return true;
    case "action-zoom-reset":
      handlers.zoomReset();
      return true;
    default:
      return false;
  }
}

import type {
  Open3dDoor,
  Open3dFurnitureItem,
  Open3dFloor,
  Open3dProject,
  Open3dPoint,
  Open3dWall,
  Open3dWindow,
  Open3dStair,
  Open3dColumn,
  Open3dAnnotation,
  Open3dMeasurement,
  Open3dTextAnnotation,
  Open3dGuide,
  Open3dElementGroup,
  Open3dBackgroundImage,
} from "../types";
import type { Open3dIdFactory } from "../project";
import { themeColorRef } from "../../shared/readThemeColor";
import { PLANNER_COLOR_TOKENS } from "../../shared/themeColorTokens";

export interface PureAction {
  type: string;
  payload?: Record<string, unknown>;
  description?: string;
  timestamp: number;
}

export interface PureActionResult {
  project: Open3dProject;
  action: PureAction;
}

export interface ApplyPureActionOptions {
  idFactory?: Open3dIdFactory;
}

function uid(factory?: Open3dIdFactory): string {
  return factory?.() ?? globalThis.crypto?.randomUUID?.() ?? Math.random().toString(36).slice(2);
}

function cloneProject(p: Open3dProject): Open3dProject {
  return JSON.parse(JSON.stringify(p));
}

function getActiveFloor(project: Open3dProject): Open3dFloor {
  const floor = project.floors.find((f) => f.id === project.activeFloorId);
  if (!floor) throw new Error(`Active floor ${project.activeFloorId} not found`);
  return floor;
}

function withUpdatedFloor(project: Open3dProject, floor: Open3dFloor): Open3dProject {
  return {
    ...project,
    floors: project.floors.map((f) => (f.id === floor.id ? floor : f)),
    updatedAt: new Date().toISOString(),
  };
}

function makeAction(type: string, payload: Record<string, unknown>, description?: string): PureAction {
  return { type, payload, description, timestamp: Date.now() };
}

// ── Wall actions ──

export function addWall(
  project: Open3dProject,
  start: Open3dPoint,
  end: Open3dPoint,
  options?: ApplyPureActionOptions,
): PureActionResult {
  const id = uid(options?.idFactory);
  const p = cloneProject(project);
  const floor = getActiveFloor(p);
  const wall: Open3dWall = {
    id,
    start: { ...start },
    end: { ...end },
    thickness: 150,
    height: 2800,
    color: themeColorRef(PLANNER_COLOR_TOKENS.importWall),
  };
  floor.walls.push(wall);
  return {
    project: withUpdatedFloor(p, floor),
    action: makeAction("ADD_WALL", { id, start, end }, "Added wall"),
  };
}

export function removeWall(project: Open3dProject, id: string): PureActionResult {
  const p = cloneProject(project);
  const floor = getActiveFloor(p);
  floor.walls = floor.walls.filter((w) => w.id !== id);
  floor.doors = floor.doors.filter((d) => d.wallId !== id);
  floor.windows = floor.windows.filter((w) => w.wallId !== id);
  return {
    project: withUpdatedFloor(p, floor),
    action: makeAction("REMOVE_WALL", { id }, "Deleted wall"),
  };
}

export function updateWall(project: Open3dProject, id: string, updates: Partial<Open3dWall>): PureActionResult {
  const p = cloneProject(project);
  const floor = getActiveFloor(p);
  const wall = floor.walls.find((w) => w.id === id);
  if (!wall) throw new Error(`Wall ${id} not found`);
  Object.assign(wall, updates);
  return {
    project: withUpdatedFloor(p, floor),
    action: makeAction("UPDATE_WALL", { id, updates }, "Updated wall"),
  };
}

export function moveWallEndpoint(
  project: Open3dProject,
  id: string,
  endpoint: "start" | "end",
  position: Open3dPoint,
): PureActionResult {
  const p = cloneProject(project);
  const floor = getActiveFloor(p);
  const wall = floor.walls.find((w) => w.id === id);
  if (!wall) throw new Error(`Wall ${id} not found`);
  wall[endpoint] = { ...position };
  return {
    project: withUpdatedFloor(p, floor),
    action: makeAction("MOVE_WALL_ENDPOINT", { id, endpoint, position }, "Moved wall endpoint"),
  };
}

export function moveWallParallel(
  project: Open3dProject,
  id: string,
  dx: number,
  dy: number,
): PureActionResult {
  const p = cloneProject(project);
  const floor = getActiveFloor(p);
  const wall = floor.walls.find((w) => w.id === id);
  if (!wall) throw new Error(`Wall ${id} not found`);
  wall.start = { x: wall.start.x + dx, y: wall.start.y + dy };
  wall.end = { x: wall.end.x + dx, y: wall.end.y + dy };
  return {
    project: withUpdatedFloor(p, floor),
    action: makeAction("MOVE_WALL_PARALLEL", { id, dx, dy }, "Moved wall"),
  };
}

export function splitWall(
  project: Open3dProject,
  id: string,
  t: number,
  options?: ApplyPureActionOptions,
): PureActionResult {
  const p = cloneProject(project);
  const floor = getActiveFloor(p);
  const wall = floor.walls.find((w) => w.id === id);
  if (!wall) throw new Error(`Wall ${id} not found`);
  if (t <= 0.001 || t >= 0.999) throw new Error("Split parameter t must be between 0.001 and 0.999");
  const newId = uid(options?.idFactory);
  const midPt: Open3dPoint = {
    x: wall.start.x + (wall.end.x - wall.start.x) * t,
    y: wall.start.y + (wall.end.y - wall.start.y) * t,
  };
  floor.walls.push({ ...wall, id: newId, start: { ...midPt }, end: { ...wall.end } });
  wall.end = { ...midPt };
  // Reassign openings
  for (const d of floor.doors) {
    if (d.wallId === id) {
      if (d.position > t) {
        d.wallId = newId;
        d.position = (d.position - t) / (1 - t);
      } else {
        d.position = d.position / t;
      }
    }
  }
  for (const w of floor.windows) {
    if (w.wallId === id) {
      if (w.position > t) {
        w.wallId = newId;
        w.position = (w.position - t) / (1 - t);
      } else {
        w.position = w.position / t;
      }
    }
  }
  return {
    project: withUpdatedFloor(p, floor),
    action: makeAction("SPLIT_WALL", { id, newId, t }, "Split wall"),
  };
}

export function duplicateWall(project: Open3dProject, id: string, options?: ApplyPureActionOptions): PureActionResult {
  const p = cloneProject(project);
  const floor = getActiveFloor(p);
  const wall = floor.walls.find((w) => w.id === id);
  if (!wall) throw new Error(`Wall ${id} not found`);
  const newId = uid(options?.idFactory);
  floor.walls.push({
    ...wall,
    id: newId,
    start: { x: wall.start.x + 300, y: wall.start.y + 300 },
    end: { x: wall.end.x + 300, y: wall.end.y + 300 },
  });
  return {
    project: withUpdatedFloor(p, floor),
    action: makeAction("DUPLICATE_WALL", { id, newId }, "Duplicated wall"),
  };
}

