// ── Import floor ──

export function importFloorIntoCurrentProject(
  project: Open3dProject,
  floor: Open3dFloor,
): PureActionResult {
  const p = cloneProject(project);
  const activeFloor = p.floors.find((f) => f.id === p.activeFloorId);
  if (!activeFloor) throw new Error("Active floor not found");
  activeFloor.walls = [...activeFloor.walls, ...floor.walls];
  activeFloor.doors = [...activeFloor.doors, ...floor.doors];
  activeFloor.windows = [...activeFloor.windows, ...floor.windows];
  activeFloor.furniture = [...activeFloor.furniture, ...floor.furniture];
  if (floor.stairs) activeFloor.stairs = [...(activeFloor.stairs || []), ...floor.stairs];
  if (floor.columns) activeFloor.columns = [...(activeFloor.columns || []), ...floor.columns];
  return {
    project: withUpdatedFloor(p, activeFloor),
    action: makeAction("IMPORT_FLOOR", { floorId: floor.id }, "Imported floor"),
  };
}

import type {
  PlannerDocument,
  PlannerJsonValue,
} from "@/features/planner/model/plannerDocument";
import type { Open3dProject, Open3dFloor, Open3dPlannerSceneEnvelope } from "../../model/types";
import { createOpen3dProject, createRectangularRoomProject } from "../../model/project";
import { createEnvelopeV1, validateEnvelope } from "../../model/operations/migration";

export interface PlannerDocumentToOpen3dResult {
  project: Open3dProject;
  envelope: Open3dPlannerSceneEnvelope;
  warnings: string[];
}

export interface Open3dToPlannerDocumentResult {
  document: PlannerDocument;
  warnings: string[];
}

function isPlannerJsonObject(value: PlannerJsonValue | undefined | null): value is Record<string, PlannerJsonValue> {
  return typeof value === "object" && value !== null && !Array.isArray(value);
}

function toPlannerJsonValue(value: Open3dPlannerSceneEnvelope): PlannerJsonValue {
  return JSON.parse(JSON.stringify(value)) as PlannerJsonValue;
}

/**
 * Convert an OOFPLWeb PlannerDocument to an Open3dProject + envelope.
 * Preserves metadata in the envelope source field and description.
 */
export function plannerDocumentToOpen3dProject(
  document: PlannerDocument,
): PlannerDocumentToOpen3dResult {
  const warnings: string[] = [];

  // Build base project from room dimensions if no scene data
  let project: Open3dProject;
  const sceneJson = document.sceneJson;

  if (isPlannerJsonObject(sceneJson) && sceneJson.type === "open3d-floorplan-project") {
    // Already an Open3D envelope stored in sceneJson
    const envelope = sceneJson as unknown as Open3dPlannerSceneEnvelope;
    const validation = validateEnvelope(envelope);
    if (validation.valid) {
      project = envelope.project;
    } else {
      warnings.push(...validation.errors.map((e) => `Envelope invalid: ${e}`));
      project = createRectangularRoomProject({
        widthMm: document.roomWidthMm,
        depthMm: document.roomDepthMm,
        name: document.name,
      });
    }
  } else if (isPlannerJsonObject(sceneJson) && sceneJson.type === "cad-suite-planner-scene") {
    // Legacy scene — cannot directly convert without legacy adapter
    warnings.push("Legacy cad-suite-planner-scene detected; using rectangular room fallback.");
    project = createRectangularRoomProject({
      widthMm: document.roomWidthMm,
      depthMm: document.roomDepthMm,
      name: document.name,
    });
  } else {
    // No recognizable scene — create a rectangular room from planner dimensions
    project = createRectangularRoomProject({
      widthMm: document.roomWidthMm,
      depthMm: document.roomDepthMm,
      name: document.name,
    });
  }

  // Overwrite metadata from PlannerDocument
  project = {
    ...project,
    id: document.id ?? project.id,
    name: project.name || document.name,
    description: [
      document.title && document.title !== document.name ? `Title: ${document.title}` : "",
      document.projectName ? `Project: ${document.projectName}` : "",
      document.clientName ? `Client: ${document.clientName}` : "",
      document.preparedBy ? `Prepared by: ${document.preparedBy}` : "",
    ]
      .filter(Boolean)
      .join("\n") || undefined,
    displayUnit: document.unitSystem === "imperial" ? "ft-in" : "mm",
    createdAt: document.createdAt ?? project.createdAt,
    updatedAt: document.updatedAt ?? project.updatedAt,
  };

  const envelope = createEnvelopeV1(project);
  return { project, envelope, warnings };
}

/**
 * Convert an Open3dProject back to an OOFPLWeb PlannerDocument.
 * Reconstructs metadata from description and envelope fields.
 */
export function open3dProjectToPlannerDocument(
  project: Open3dProject,
  envelope?: Open3dPlannerSceneEnvelope,
): Open3dToPlannerDocumentResult {
  const warnings: string[] = [];

  // Parse description back into metadata fields
  let title: string | null = null;
  let projectName: string | null = null;
  let clientName: string | null = null;
  let preparedBy: string | null = null;

  if (project.description) {
    const lines = project.description.split("\n");
    for (const line of lines) {
      if (line.startsWith("Title: ")) title = line.slice("Title: ".length);
      else if (line.startsWith("Project: ")) projectName = line.slice("Project: ".length);
      else if (line.startsWith("Client: ")) clientName = line.slice("Client: ".length);
      else if (line.startsWith("Prepared by: ")) preparedBy = line.slice("Prepared by: ".length);
    }
  }

  // Derive room dimensions from first floor walls
  let roomWidthMm = 6000;
  let roomDepthMm = 8000;
  const floor = project.floors[0];
  if (floor && floor.walls.length >= 4) {
    const xs = floor.walls.flatMap((w) => [w.start.x, w.end.x]);
    const ys = floor.walls.flatMap((w) => [w.start.y, w.end.y]);
    const minX = Math.min(...xs);
    const maxX = Math.max(...xs);
    const minY = Math.min(...ys);
    const maxY = Math.max(...ys);
    roomWidthMm = Math.max(1, Math.round(maxX - minX));
    roomDepthMm = Math.max(1, Math.round(maxY - minY));
  } else {
    warnings.push("No recognizable rectangular room in first floor; using default dimensions.");
  }

  const unitSystem: "metric" | "imperial" = project.displayUnit === "ft-in" ? "imperial" : "metric";

  // Store the full Open3D envelope in sceneJson so round-trip preserves everything
  const sceneJson = envelope ?? createEnvelopeV1(project);

  const document: PlannerDocument = {
    schemaVersion: 1,
    id: project.id,
    name: project.name,
    title: title ?? project.name,
    projectName,
    clientName,
    preparedBy,
    roomWidthMm,
    roomDepthMm,
    seatTarget: 10,
    unitSystem,
    sceneJson: toPlannerJsonValue(sceneJson),
    itemCount: 0,
    thumbnailUrl: null,
    status: "draft",
    createdAt: project.createdAt,
    updatedAt: project.updatedAt,
  };

  return { document, warnings };
}

/**
 * Phase 06 Export Utilities
 *
 * Multi-format export for Open3D floor plans:
 * - JSON: Full project serialization
 * - SVG: Vector graphics for web/print
 * - PNG: Rasterized floor plan
 * - PDF: Multi-page document with title block
 * - DXF: CAD handoff format
 *
 * All internal geometry uses canonical millimetres.
 * Display values use the project's displayUnit.
 */

import type {
  Open3dProject,
  Open3dFloor,
  Open3dWall,
  Open3dDoor,
  Open3dWindow,
  Open3dFurnitureItem,
  Open3dDisplayUnit,
} from "../../model/types";
import { displayCmFromCanonicalMm, displayMFromCanonicalMm, displayInFromCanonicalMm, displayFtInFromCanonicalMm } from "../../catalog/unitConversion";
import {
  readExportPaintColors,
  resolvePaintColor,
} from "../readThemeColor";
import { PLANNER_COLOR_TOKENS } from "../themeColorTokens";

// ── Types ──

/** Result from an export operation */
export interface ExportResult {
  success: boolean;
  data?: string | Blob;
  error?: string;
}

/** PDF export settings */
export interface PdfExportSettings {
  title?: string;
  include3D?: boolean;
  includeRoomSchedule?: boolean;
  orientation?: "portrait" | "landscape";
  format?: "a4" | "letter";
  showDimensions?: boolean;
  showRoomNames?: boolean;
  showFurnitureLabels?: boolean;
}

/** Default PDF settings */
export const DEFAULT_PDF_SETTINGS: PdfExportSettings = {
  include3D: false,
  includeRoomSchedule: true,
  orientation: "landscape",
  format: "a4",
  showDimensions: true,
  showRoomNames: true,
  showFurnitureLabels: true,
};

// ── Unit formatting ──

/**
 * Format a measurement value according to display unit.
 * @param mmValue - Value in millimetres (internal canonical)
 * @param displayUnit - Target display unit
 * @returns Formatted string with unit
 */
export function formatMeasurement(mmValue: number, displayUnit: Open3dDisplayUnit): string {
  const converters: Record<Open3dDisplayUnit, (v: number) => string> = {
    mm: (v) => `${Math.round(v)} mm`,
    cm: (v) => `${displayCmFromCanonicalMm(v)} cm`,
    m: (v) => `${displayMFromCanonicalMm(v)} m`,
    in: (v) => `${displayInFromCanonicalMm(v)} in`,
    "ft-in": displayFtInFromCanonicalMm,
  };
  return converters[displayUnit](mmValue);
}

/**
 * Format area in display units (always square of the length unit).
 */
export function formatArea(sqMm: number, displayUnit: Open3dDisplayUnit): string {
  const unitConverters: Record<Open3dDisplayUnit, (v: number) => string> = {
    mm: (v) => `${Math.round(v)} mm²`,
    cm: (v) => `${Math.round(v / 100)} cm²`,
    m: (v) => `${Math.round(v / 1000000)} m²`,
    in: (v) => `${Math.round(v / 645.16)} in²`,
    "ft-in": (v) => `${Math.round(v / 92903)} ft²`,
  };
  return unitConverters[displayUnit](sqMm);
}

// ── Geometry helpers ──

/** Calculate wall length in mm */
export function getWallLengthMm(wall: Open3dWall): number {
  const dx = wall.end.x - wall.start.x;
  const dy = wall.end.y - wall.start.y;
  return Math.sqrt(dx * dx + dy * dy);
}

/** Calculate floor bounding box */
export function getFloorBounds(floor: Open3dFloor): {
  minX: number;
  minY: number;
  maxX: number;
  maxY: number;
} {
  let minX = Infinity;
  let minY = Infinity;
  let maxX = -Infinity;
  let maxY = -Infinity;

  for (const w of floor.walls) {
    minX = Math.min(minX, w.start.x, w.end.x);
    minY = Math.min(minY, w.start.y, w.end.y);
    maxX = Math.max(maxX, w.start.x, w.end.x);
    maxY = Math.max(maxY, w.start.y, w.end.y);
  }

  for (const f of floor.furniture) {
    const fw = f.width ?? 500;
    const fd = f.depth ?? 500;
    minX = Math.min(minX, f.position.x - fw / 2);
    minY = Math.min(minY, f.position.y - fd / 2);
    maxX = Math.max(maxX, f.position.x + fw / 2);
    maxY = Math.max(maxY, f.position.y + fd / 2);
  }

  return { minX, minY, maxX, maxY };
}

// ── JSON Export ──

/**
 * Serialize a project to JSON string.
 * @param project - The project to serialize
 * @param pretty - Whether to pretty-print
 * @returns JSON string
 */
export function exportAsJSON(project: Open3dProject, pretty = false): string {
  const envelope = {
    type: "open3d-floorplan-project",
    version: 1,
    units: "mm" as const,
    displayUnit: project.displayUnit,
    source: "native-open3d" as const,
    project,
  };
  return JSON.stringify(envelope, null, pretty ? 2 : 0);
}

/**
 * Download a blob as a file.
 */
function downloadBlob(blob: Blob, filename: string): void {
  const url = URL.createObjectURL(blob);
  const a = document.createElement("a");
  a.href = url;
  a.download = filename;
  document.body.appendChild(a);
  a.click();
  document.body.removeChild(a);
  URL.revokeObjectURL(url);
}

/**
 * Download JSON export.
 */
export function downloadJSON(project: Open3dProject, filename?: string): void {
  const json = exportAsJSON(project, true);
  const blob = new Blob([json], { type: "application/json" });
  downloadBlob(blob, filename ?? `${project.name || "floorplan"}.json`);
}

// ── SVG Export ──

/** Escape text for safe SVG embedding */
function escapeXml(s: string): string {
  return s.replace(/&/g, "&amp;")
    .replace(/</g, "&lt;")
    .replace(/>/g, "&gt;")
    .replace(/"/g, "&quot;")
    .replace(/'/g, "&apos;");
}

/**
 * Generate SVG from floor geometry.
 * Reuses Phase 03A SVG generation pipeline patterns.
 */
export function exportAsSVG(project: Open3dProject, floor?: Open3dFloor): string {
  const targetFloor = floor ?? project.floors.find((f) => f.id === project.activeFloorId) ?? project.floors[0];
  if (!targetFloor || targetFloor.walls.length === 0) {
    return "";
  }

  const { minX, minY, maxX, maxY } = getFloorBounds(targetFloor);
  const pad = 2000; // 2m padding in mm
  const viewWidth = maxX - minX + pad * 2;
  const viewHeight = maxY - minY + pad * 2;
  const displayUnit = project.displayUnit;

  let paths = "";
  const colors = readExportPaintColors();

  // Draw walls
  for (let wi = 0; wi < targetFloor.walls.length; wi++) {
    const w = targetFloor.walls[wi];
    const x1 = w.start.x - minX + pad;
    const y1 = w.start.y - minY + pad;
    const x2 = w.end.x - minX + pad;
    const y2 = w.end.y - minY + pad;

    paths += `  <line x1="${x1}" y1="${y1}" x2="${x2}" y2="${y2}" stroke="${colors.wallStroke}" stroke-width="${w.thickness}" stroke-linecap="round"/>\n`;

    // Dimension label
    if (project.displayUnit) {
      const len = getWallLengthMm(w);
      const mx = (x1 + x2) / 2;
      const my = (y1 + y2) / 2;
      paths += `  <text x="${mx}" y="${my - 30}" text-anchor="middle" font-size="40" fill="${colors.dimensionLabel}" font-family="sans-serif">${formatMeasurement(len, displayUnit)}</text>\n`;
    }
  }

  // Draw doors as circles
  for (const d of targetFloor.doors) {
    const wall = targetFloor.walls.find((wl) => wl.id === d.wallId);
    if (!wall) continue;

    const wdx = wall.end.x - wall.start.x;
    const wdy = wall.end.y - wall.start.y;
    const wlen = Math.sqrt(wdx * wdx + wdy * wdy);
    if (wlen === 0) continue;

    const px = wall.start.x + wdx * d.position - minX + pad;
    const py = wall.start.y + wdy * d.position - minY + pad;

    paths += `  <circle cx="${px}" cy="${py}" r="15" fill="${colors.doorFill}"/>\n`;
  }

  // Draw windows
  for (const win of targetFloor.windows) {
    const wall = targetFloor.walls.find((wl) => wl.id === win.wallId);
    if (!wall) continue;

    const wdx = wall.end.x - wall.start.x;
    const wdy = wall.end.y - wall.start.y;
    const wlen = Math.sqrt(wdx * wdx + wdy * wdy);
    if (wlen === 0) continue;

    const ux = wdx / wlen;
    const uy = wdy / wlen;

    const cx = wall.start.x + wdx * win.position - minX + pad;
    const cy = wall.start.y + wdy * win.position - minY + pad;
    const halfW = win.width / 2;

    // Draw as two parallel lines
    const nx = -uy * 10;
    const ny = ux * 10;

    paths += `  <line x1="${cx - ux * halfW + nx}" y1="${cy - uy * halfW + ny}" x2="${cx + ux * halfW + nx}" y2="${cy + uy * halfW + ny}" stroke="${colors.windowStroke}" stroke-width="8"/>\n`;
    paths += `  <line x1="${cx - ux * halfW - nx}" y1="${cy - uy * halfW - ny}" x2="${cx + ux * halfW - nx}" y2="${cy + uy * halfW - ny}" stroke="${colors.windowStroke}" stroke-width="8"/>\n`;
  }

  // Draw furniture
  for (const fi of targetFloor.furniture) {
    const fx = fi.position.x - minX + pad;
    const fy = fi.position.y - minY + pad;
    const fw = fi.width ?? 500;
    const fd = fi.depth ?? 500;
    const rot = fi.rotation ?? 0;
    const color = resolvePaintColor(fi.color, PLANNER_COLOR_TOKENS.furnitureDefault);

    paths += `  <g transform="translate(${fx},${fy}) rotate(${rot})">\n`;
    paths += `    <rect x="${-fw / 2}" y="${-fd / 2}" width="${fw}" height="${fd}" fill="${color}" stroke="${colors.furnitureStroke}" stroke-width="2" rx="5" opacity="0.8"/>\n`;
    paths += `  </g>\n`;
  }

  // Title
  const titleY = 80;
  paths += `  <text x="60" y="${titleY}" font-size="60" font-weight="bold" fill="${colors.titleText}" font-family="sans-serif">${escapeXml(project.name)}</text>\n`;
  paths += `  <text x="60" y="${titleY + 70}" font-size="40" fill="${colors.subtitleText}" font-family="sans-serif">${escapeXml(targetFloor.name)}</text>\n`;

  const svg = `<?xml version="1.0" encoding="UTF-8"?>
<svg xmlns="http://www.w3.org/2000/svg" viewBox="0 0 ${viewWidth} ${viewHeight}" width="${viewWidth}" height="${viewHeight}">
  <rect width="100%" height="100%" fill="${colors.background}"/>
${paths}</svg>`;

  return svg;
}

/**
 * Download SVG export.
 */
export function downloadSVG(project: Open3dProject, floor?: Open3dFloor): void {
  const svg = exportAsSVG(project, floor);
  if (!svg) return;

  const blob = new Blob([svg], { type: "image/svg+xml" });
  downloadBlob(blob, `${project.name || "floorplan"}.svg`);
}

// ── Optional export dependency shapes (structural types avoid typeof-import parse issues in coverage remapping) ──

interface PdfPageSize {
  getWidth(): number;
  getHeight(): number;
}

interface PdfDocument {
  internal: { pageSize: PdfPageSize };
  setDrawColor(color: number): void;
  setLineWidth(width: number): void;
  rect(x: number, y: number, w: number, h: number): void;
  line(x1: number, y1: number, x2: number, y2: number): void;
  setFontSize(size: number): void;
  setFont(family: string, style: string): void;
  text(text: string, x: number, y: number): void;
  addImage(data: string, format: string, x: number, y: number, w: number, h: number): void;
  addPage(): void;
  output(type: "blob"): Blob;
}

type PdfConstructor = new (options?: {
  orientation?: string;
  unit?: string;
  format?: string;
}) => PdfDocument;

interface DxfDrawing {
  setUnits(unit: string): void;
  addLayer(name: string, color: number, style: string): void;
  setActiveLayer(name: string): void;
  drawPolyline(points: [number, number][]): void;
  drawText(
    x: number,
    y: number,
    size: number,
    angle: number,
    text: string,
    halign: string,
    valign: string,
  ): void;
  drawArc(x: number, y: number, r: number, startAngle: number, endAngle: number): void;
  drawLine(x1: number, y1: number, x2: number, y2: number): void;
  toDxfString(): string;
}

type DxfConstructor = new () => DxfDrawing;

// ── PNG Export ──

/**
 * Render floor to offscreen canvas and export as PNG.
 * @param canvas - Source canvas (viewport capture fallback)
 * @param project - Optional project for full render
 * @param floorIndex - Which floor to render (default: active)
 * @returns Promise resolving to PNG blob
 */
export async function exportAsPNG(
  canvas: HTMLCanvasElement,
  project?: Open3dProject,
  floorIndex = 0,
): Promise<Blob | null> {
  // If no project, use canvas directly
  if (!project) {
    return new Promise((resolve) => {
      canvas.toBlob((blob) => resolve(blob));
    });
  }

  const floor = project.floors[floorIndex] ?? project.floors.find((f) => f.id === project.activeFloorId) ?? project.floors[0];
  if (!floor || floor.walls.length === 0) {
    return null;
  }

  const { minX, minY, maxX, maxY } = getFloorBounds(floor);
  const pad = 2000;
  const width = maxX - minX + pad * 2;
  const height = maxY - minY + pad * 2;
  const scale = 2; // High-res export

  const offscreen = document.createElement("canvas");
  offscreen.width = width * scale;
  offscreen.height = height * scale;
  const ctx = offscreen.getContext("2d");
  if (!ctx) return null;

  ctx.scale(scale, scale);
  const colors = readExportPaintColors();
  ctx.fillStyle = colors.background;
  ctx.fillRect(0, 0, width, height);

  // Draw walls
  ctx.strokeStyle = colors.wallStroke;
  ctx.lineCap = "round";
  for (const wall of floor.walls) {
    ctx.lineWidth = wall.thickness;
    ctx.beginPath();
    ctx.moveTo(wall.start.x - minX + pad, wall.start.y - minY + pad);
    ctx.lineTo(wall.end.x - minX + pad, wall.end.y - minY + pad);
    ctx.stroke();

    // Dimension
    const len = getWallLengthMm(wall);
    const mx = (wall.start.x + wall.end.x) / 2 - minX + pad;
    const my = (wall.start.y + wall.end.y) / 2 - minY + pad;
    ctx.fillStyle = colors.dimensionLabel;
    ctx.font = "bold 40px sans-serif";
    ctx.textAlign = "center";
    ctx.fillText(formatMeasurement(len, project.displayUnit), mx, my - 40);
  }

  // Draw doors
  for (const d of floor.doors) {
    const wall = floor.walls.find((wl) => wl.id === d.wallId);
    if (!wall) continue;

    const wdx = wall.end.x - wall.start.x;
    const wdy = wall.end.y - wall.start.y;
    const px = wall.start.x + wdx * d.position - minX + pad;
    const py = wall.start.y + wdy * d.position - minY + pad;

    ctx.fillStyle = colors.doorFill;
    ctx.beginPath();
    ctx.arc(px, py, 15, 0, Math.PI * 2);
    ctx.fill();
  }

  // Draw furniture
  for (const fi of floor.furniture) {
    const fx = fi.position.x - minX + pad;
    const fy = fi.position.y - minY + pad;
    const fw = fi.width ?? 500;
    const fd = fi.depth ?? 500;
    const rot = ((fi.rotation ?? 0) * Math.PI) / 180;
    const color = resolvePaintColor(fi.color, PLANNER_COLOR_TOKENS.furnitureDefault);

    ctx.save();
    ctx.translate(fx, fy);
    ctx.rotate(rot);
    ctx.globalAlpha = 0.8;
    ctx.fillStyle = color;
    ctx.fillRect(-fw / 2, -fd / 2, fw, fd);
    ctx.strokeStyle = colors.furnitureStroke;
    ctx.lineWidth = 2;
    ctx.strokeRect(-fw / 2, -fd / 2, fw, fd);
    ctx.restore();
  }

  // Title
  ctx.fillStyle = colors.titleText;
  ctx.font = "bold 60px sans-serif";
  ctx.textAlign = "left";
  ctx.fillText(`${project.name} — ${floor.name}`, 80, 100);

  return new Promise((resolve) => {
    offscreen.toBlob((blob) => resolve(blob));
  });
}

/**
 * Download PNG export.
 */
export async function downloadPNG(
  canvas: HTMLCanvasElement,
  project?: Open3dProject,
  filename?: string,
): Promise<void> {
  const blob = await exportAsPNG(canvas, project);
  if (blob) {
    downloadBlob(blob, filename ?? `${project?.name ?? "floorplan"}.png`);
  }
}

// ── PDF Export ──

/**
 * Generate PDF with title block and floor plan.
 * Note: Requires jspdf to be installed as a dependency.
 */
export async function exportAsPDF(
  project: Open3dProject,
  settings: PdfExportSettings = DEFAULT_PDF_SETTINGS,
): Promise<Blob | null> {
  // Dynamic import jspdf - this allows the function to work
  // when jspdf is not available (will return null)
  let jsPDF: PdfConstructor | null = null;
  try {
    const mod = await import("jspdf");
    jsPDF = mod.default as PdfConstructor;
  } catch {
    console.warn("jspdf not available for PDF export");
    return null;
  }

  const floor = project.floors.find((f) => f.id === project.activeFloorId) ?? project.floors[0];
  if (!floor || floor.walls.length === 0) {
    return null;
  }

  const { minX, minY, maxX, maxY } = getFloorBounds(floor);
  const pad = 2000;
  const planW = maxX - minX + pad * 2;
  const planH = maxY - minY + pad * 2;
  const scale = 2;

  // Create offscreen canvas for floor plan
  const offscreen = document.createElement("canvas");
  offscreen.width = planW * scale;
  offscreen.height = planH * scale;
  const ctx = offscreen.getContext("2d");
  if (!ctx) return null;

  ctx.scale(scale, scale);
  const colors = readExportPaintColors();
  ctx.fillStyle = colors.background;
  ctx.fillRect(0, 0, planW, planH);

  // Draw floor plan to canvas
  // Walls
  ctx.strokeStyle = colors.wallStroke;
  ctx.lineCap = "round";
  for (const wall of floor.walls) {
    ctx.lineWidth = wall.thickness;
    ctx.beginPath();
    ctx.moveTo(wall.start.x - minX + pad, wall.start.y - minY + pad);
    ctx.lineTo(wall.end.x - minX + pad, wall.end.y - minY + pad);
    ctx.stroke();
  }

  // Doors
  for (const d of floor.doors) {
    const wall = floor.walls.find((wl) => wl.id === d.wallId);
    if (!wall) continue;
    const wdx = wall.end.x - wall.start.x;
    const wdy = wall.end.y - wall.start.y;
    const px = wall.start.x + wdx * d.position - minX + pad;
    const py = wall.start.y + wdy * d.position - minY + pad;
    ctx.fillStyle = colors.doorFill;
    ctx.beginPath();
    ctx.arc(px, py, 15, 0, Math.PI * 2);
    ctx.fill();
  }

  // Furniture
  for (const fi of floor.furniture) {
    const fx = fi.position.x - minX + pad;
    const fy = fi.position.y - minY + pad;
    const fw = fi.width ?? 500;
    const fd = fi.depth ?? 500;
    const rot = ((fi.rotation ?? 0) * Math.PI) / 180;
    const color = resolvePaintColor(fi.color, PLANNER_COLOR_TOKENS.furnitureDefault);

    ctx.save();
    ctx.translate(fx, fy);
    ctx.rotate(rot);
    ctx.globalAlpha = 0.8;
    ctx.fillStyle = color;
    ctx.fillRect(-fw / 2, -fd / 2, fw, fd);
    ctx.restore();
  }

  // Create PDF
  const orientation = settings.orientation ?? "landscape";
  const format = settings.format ?? "a4";
  const pdf = new jsPDF({ orientation, unit: "mm", format });

  const pageWidth = pdf.internal.pageSize.getWidth();
  const pageHeight = pdf.internal.pageSize.getHeight();
  const margin = 10;
  const titleBlockH = 25;

  // Page border
  pdf.setDrawColor(40);
  pdf.setLineWidth(0.5);
  pdf.rect(margin, margin, pageWidth - margin * 2, pageHeight - margin * 2);

  // Draw title block
  const tbY = pageHeight - margin - titleBlockH;
  const tbW = pageWidth - margin * 2;
  pdf.setDrawColor(40);
  pdf.setLineWidth(0.4);
  pdf.rect(margin, tbY, tbW, titleBlockH);

  // Vertical dividers
  const col1 = margin + tbW * 0.45;
  const col2 = margin + tbW * 0.7;
  pdf.line(col1, tbY, col1, tbY + titleBlockH);
  pdf.line(col2, tbY, col2, tbY + titleBlockH);

  // Project name
  pdf.setFontSize(14);
  pdf.setFont("helvetica", "bold");
  pdf.text(project.name ?? "Untitled Project", margin + 5, tbY + 10);
  pdf.setFontSize(9);
  pdf.setFont("helvetica", "normal");
  pdf.text(floor.name, margin + 5, tbY + 18);

  // Date / units
  const today = new Date().toLocaleDateString("en-US", {
    year: "numeric",
    month: "long",
    day: "numeric",
  });
  pdf.setFontSize(9);
  pdf.text(`Date: ${today}`, col1 + 5, tbY + 10);
  pdf.text(`Units: ${project.displayUnit}`, col1 + 5, tbY + 18);

  // Branding
  pdf.setFontSize(10);
  pdf.setFont("helvetica", "bold");
  pdf.text("openplan3d.com", col2 + 5, tbY + 10);
  pdf.setFont("helvetica", "normal");
  pdf.setFontSize(7);
  pdf.text("Created with Open 3D Floor Planner", col2 + 5, tbY + 18);

  // Render floor plan to PDF
  const drawAreaW = pageWidth - margin * 2 - 4;
  const drawAreaH = pageHeight - margin * 2 - titleBlockH - 6;
  const aspect = planW / planH;
  let imgW = drawAreaW;
  let imgH = drawAreaW / aspect;
  if (imgH > drawAreaH) {
    imgH = drawAreaH;
    imgW = drawAreaH * aspect;
  }
  const imgX = margin + 2 + (drawAreaW - imgW) / 2;
  const imgY = margin + 2 + (drawAreaH - imgH) / 2;

  const imgData = offscreen.toDataURL("image/png");
  pdf.addImage(imgData, "PNG", imgX, imgY, imgW, imgH);

  // Page 2: Room schedule
  if (settings.includeRoomSchedule) {
    pdf.addPage();
    pdf.setDrawColor(40);
    pdf.setLineWidth(0.5);
    pdf.rect(margin, margin, pageWidth - margin * 2, pageHeight - margin * 2);

    pdf.setFontSize(16);
    pdf.setFont("helvetica", "bold");
    pdf.text("Room Schedule", margin + 6, margin + 12);

    // Basic room info
    pdf.setFontSize(10);
    pdf.setFont("helvetica", "normal");
    const statsY = margin + 25;
    pdf.text(`Total walls: ${floor.walls.length}`, margin + 6, statsY);
    pdf.text(`Total doors: ${floor.doors.length}`, margin + 40, statsY);
    pdf.text(`Total windows: ${floor.windows.length}`, margin + 70, statsY);
    pdf.text(`Total furniture: ${floor.furniture.length}`, margin + 105, statsY);

    // Title block on page 2
    pdf.setDrawColor(40);
    pdf.setLineWidth(0.4);
    pdf.rect(margin, tbY, tbW, titleBlockH);
    pdf.line(col1, tbY, col1, tbY + titleBlockH);
    pdf.line(col2, tbY, col2, tbY + titleBlockH);
    pdf.setFontSize(14);
    pdf.setFont("helvetica", "bold");
    pdf.text(project.name ?? "Untitled", margin + 5, tbY + 10);
    pdf.setFontSize(9);
    pdf.text(`Page 2`, margin + 5, tbY + 18);
    pdf.setFontSize(10);
    pdf.text(`Date: ${today}`, col1 + 5, tbY + 10);
  }

  return pdf.output("blob");
}

/**
 * Download PDF export.
 */
export async function downloadPDF(
  project: Open3dProject,
  settings?: PdfExportSettings,
  filename?: string,
): Promise<void> {
  const blob = await exportAsPDF(project, settings);
  if (blob) {
    downloadBlob(blob, filename ?? `${project.name ?? "floorplan"}.pdf`);
  }
}

// ── DXF Export ──

/**
 * Generate DXF for CAD handoff.
 * Note: Requires dxf-writer to be installed as a dependency.
 */
export async function exportAsDXF(project: Open3dProject): Promise<string | null> {
  // Dynamic import dxf-writer
  let Drawing: DxfConstructor | null = null;
  try {
    const mod = await import("dxf-writer");
    Drawing = mod.default as DxfConstructor;
  } catch {
    console.warn("dxf-writer not available for DXF export");
    return null;
  }

  const floor = project.floors.find((f) => f.id === project.activeFloorId) ?? project.floors[0];
  if (!floor || floor.walls.length === 0) {
    return null;
  }

  const d = new Drawing();
  d.setUnits("Millimeters");

  // Layers
  const LAYER_COLORS = {
    WALLS: 7,
    DOORS: 30,
    WINDOWS: 5,
    FURNITURE: 3,
    DIMENSIONS: 8,
  };

  d.addLayer("WALLS", LAYER_COLORS.WALLS, "CONTINUOUS");
  d.addLayer("DOORS", LAYER_COLORS.DOORS, "CONTINUOUS");
  d.addLayer("WINDOWS", LAYER_COLORS.WINDOWS, "CONTINUOUS");
  d.addLayer("FURNITURE", LAYER_COLORS.FURNITURE, "CONTINUOUS");
  d.addLayer("DIMENSIONS", LAYER_COLORS.DIMENSIONS, "CONTINUOUS");

  // Draw walls as rectangles
  d.setActiveLayer("WALLS");
  for (const w of floor.walls) {
    const dx = w.end.x - w.start.x;
    const dy = w.end.y - w.start.y;
    const len = Math.sqrt(dx * dx + dy * dy);
    if (len === 0) continue;

    const half = w.thickness / 2;
    const nx = (-dy / len) * half;
    const ny = (dx / len) * half;

    // Four corners of wall rectangle
    const corners: [number, number][] = [
      [w.start.x + nx, w.start.y + ny],
      [w.end.x + nx, w.end.y + ny],
      [w.end.x - nx, w.end.y - ny],
      [w.start.x - nx, w.start.y - ny],
    ];
    corners.push(corners[0]); // Close

    d.drawPolyline(corners);
  }

  // Draw dimensions
  d.setActiveLayer("DIMENSIONS");
  for (const w of floor.walls) {
    const len = getWallLengthMm(w);
    const mx = (w.start.x + w.end.x) / 2;
    const my = (w.start.y + w.end.y) / 2;
    const angle = (Math.atan2(w.end.y - w.start.y, w.end.x - w.start.x) * 180) / Math.PI;
    d.drawText(mx, my + 50, 20, angle, `${Math.round(len)} mm`, "center", "bottom");
  }

  // Draw doors as arcs
  d.setActiveLayer("DOORS");
  for (const door of floor.doors) {
    const wall = floor.walls.find((w) => w.id === door.wallId);
    if (!wall) continue;

    const wdx = wall.end.x - wall.start.x;
    const wdy = wall.end.y - wall.start.y;
    const wlen = Math.sqrt(wdx * wdx + wdy * wdy);
    if (wlen === 0) continue;

    const hx = wall.start.x + wdx * door.position;
    const hy = wall.start.y + wdy * door.position;
    const r = door.width / 2;
    const wallAngle = (Math.atan2(wdy, wdx) * 180) / Math.PI;

    const startAngle = door.swingDirection === "left" ? wallAngle : wallAngle - 90;
    const endAngle = door.swingDirection === "left" ? wallAngle + 90 : wallAngle;
    d.drawArc(hx, hy, r, startAngle, endAngle);

    const panelAngle = ((door.swingDirection === "left" ? wallAngle : wallAngle - 90) * Math.PI) / 180;
    d.drawLine(hx, hy, hx + Math.cos(panelAngle) * r, hy + Math.sin(panelAngle) * r);
  }

  // Draw windows as parallel lines
  d.setActiveLayer("WINDOWS");
  for (const win of floor.windows) {
    const wall = floor.walls.find((w) => w.id === win.wallId);
    if (!wall) continue;

    const wdx = wall.end.x - wall.start.x;
    const wdy = wall.end.y - wall.start.y;
    const wlen = Math.sqrt(wdx * wdx + wdy * wdy);
    if (wlen === 0) continue;

    const ux = wdx / wlen;
    const uy = wdy / wlen;
    const nx = -uy;
    const ny = ux;

    const cx = wall.start.x + wdx * win.position;
    const cy = wall.start.y + wdy * win.position;
    const halfW = win.width / 2;
    const gap = 10;

    for (const offset of [-gap, gap]) {
      const ox = nx * offset;
      const oy = ny * offset;
      d.drawLine(
        cx - ux * halfW + ox,
        cy - uy * halfW + oy,
        cx + ux * halfW + ox,
        cy + uy * halfW + oy,
      );
    }
  }

  // Draw furniture
  d.setActiveLayer("FURNITURE");
  for (const fi of floor.furniture) {
    const fw = fi.width ?? 500;
    const fd = fi.depth ?? 500;
    const fx = fi.position.x;
    const fy = fi.position.y;
    const rot = ((fi.rotation ?? 0) * Math.PI) / 180;

    const hw = fw / 2;
    const hd = fd / 2;
    const corners: [number, number][] = [
      [-hw, -hd],
      [hw, -hd],
      [hw, hd],
      [-hw, hd],
    ];
    const rotated = corners.map(([cx, cy]) => {
      const rx = cx * Math.cos(rot) - cy * Math.sin(rot);
      const ry = cx * Math.sin(rot) + cy * Math.cos(rot);
      return [fx + rx, fy + ry] as [number, number];
    });
    rotated.push(rotated[0]);
    d.drawPolyline(rotated);
  }

  return d.toDxfString();
}

/**
 * Download DXF export.
 */
export async function downloadDXF(project: Open3dProject, filename?: string): Promise<void> {
  const dxf = await exportAsDXF(project);
  if (dxf) {
    const blob = new Blob([dxf], { type: "application/dxf" });
    downloadBlob(blob, filename ?? `${project.name ?? "floorplan"}.dxf`);
  }
}

/**
 * Phase 06 Import Utilities
 *
 * Multi-format import for Open3D floor plans:
 * - JSON: Standard project format
 * - RoomPlan: Apple RoomPlan JSON format
 *
 * Includes validation, error recovery, and schema checking.
 */

import type {
  Open3dProject,
  Open3dFloor,
  Open3dWall,
  Open3dDoor,
  Open3dWindow,
  Open3dFurnitureItem,
  Open3dRoom,
  Open3dPoint,
  Open3dDisplayUnit,
} from "../../model/types";
import { themeColorRef } from "../readThemeColor";
import { PLANNER_COLOR_TOKENS } from "../themeColorTokens";
import {
  importFromJson,
  parseJsonToEnvelope,
  validateEnvelopeStructure,
  recoverFromErrors,
  DEFAULT_IMPORT_LIMITS,
  type ImportValidationError,
  type ImportLimits,
  type ImportResult,
} from "./jsonImport";

// ── Types ──

/** RoomPlan import options */
export interface RoomPlanImportOptions {
  straighten?: boolean;
  orthogonal?: boolean;
  angleTolerance?: number;
  mergeDistance?: number;
}

/** Import format detection result */
export interface FormatDetectionResult {
  format: "json" | "roomplan" | "unknown";
  confidence: number;
}

// ── JSON Import ──

/**
 * Parse and validate JSON string to a project.
 * @param jsonString - The JSON string to import
 * @param limits - Optional custom limits
 * @returns Import result with project and errors
 */
export function importFromJSON(
  jsonString: string,
  limits: ImportLimits = DEFAULT_IMPORT_LIMITS,
): ImportResult {
  // Use existing jsonImport module
  return importFromJson(jsonString, limits);
}

/**
 * Import from JSON with error recovery.
 * Attempts to fix common issues and re-validate.
 */
export function importFromJSONWithRecovery(
  jsonString: string,
  limits: ImportLimits = DEFAULT_IMPORT_LIMITS,
): ImportResult & { recovered: string[] } {
  const result = importFromJSON(jsonString, limits);

  // If successful or has warnings but no errors, try recovery
  const hasErrors = result.errors.some((e) => e.severity === "error");
  if (hasErrors && result.project) {
    // Try to recover from errors
    const envelopeResult = parseJsonToEnvelope(jsonString);
    if (envelopeResult.envelope) {
      const { recovered } = recoverFromErrors(envelopeResult.envelope);
      return { ...result, recovered };
    }
  }

  return { ...result, recovered: [] };
}

// ── RoomPlan Import ──

// RoomPlan uses meters in XZ plane, we use mm in XY plane
const ROOMPLAN_TO_MM = 1000;

/**
 * Generate a unique ID for imported elements.
 */
function generateId(): string {
  return Math.random().toString(36).substring(2, 10);
}

/**
 * Convert RoomPlan point (meters in XZ) to our point (mm in XY).
 */
function toOurPoint(rpX: number, rpZ: number): Open3dPoint {
  return { x: rpX * ROOMPLAN_TO_MM, y: rpZ * ROOMPLAN_TO_MM };
}

/**
 * Get position from RoomPlan transform matrix.
 */
function getPositionFromTransform(t: number[]): { x: number; y: number; z: number } {
  return { x: t[12] ?? 0, y: t[13] ?? 0, z: t[14] ?? 0 };
}

/**
 * Get Y rotation from transform matrix.
 */
function getYRotation(t: number[]): number {
  return Math.atan2(t[8] ?? 0, t[0] ?? 1);
}

/**
 * Project a point onto a wall segment.
 */
function projectOntoWall(wall: Open3dWall, pt: Open3dPoint): number {
  const dx = wall.end.x - wall.start.x;
  const dy = wall.end.y - wall.start.y;
  const lenSq = dx * dx + dy * dy;
  if (lenSq === 0) return 0.5;
  const t = ((pt.x - wall.start.x) * dx + (pt.y - wall.start.y) * dy) / lenSq;
  return Math.max(0.01, Math.min(0.99, t));
}

/**
 * Map RoomPlan door category to our door type.
 */
function mapDoorType(category: unknown): Open3dDoor["type"] {
  if (typeof category === "string") {
    if (category === "doubleDoor" || category === "french") return "double";
    if (category === "slidingDoor") return "sliding";
    if (category === "foldingDoor") return "bifold";
    if (category === "pocketDoor") return "pocket";
  }
  return "single";
}

/**
 * Map RoomPlan window category to our window type.
 */
function mapWindowType(category: unknown): Open3dWindow["type"] {
  if (typeof category === "string") {
    if (category === "slidingWindow") return "sliding";
    if (category === "bayWindow") return "bay";
    if (category === "casementWindow") return "casement";
    if (category === "fixedWindow") return "fixed";
  }
  return "standard";
}

/**
 * Map RoomPlan section label to room name.
 */
function mapSectionLabel(label: string): string {
  const labelMap: Record<string, string> = {
    livingRoom: "Living Room",
    bedroom: "Bedroom",
    kitchen: "Kitchen",
    bathroom: "Bathroom",
    diningRoom: "Dining Room",
    laundryRoom: "Laundry",
    office: "Office",
    hallway: "Hallway",
    garage: "Garage",
    closet: "Closet",
    pantry: "Pantry",
    entryway: "Entryway",
  };
  return labelMap[label] ?? label;
}

/**
 * Simplify RoomPlan walls by snapping to orthogonal and merging endpoints.
 */
function straightenWalls(
  walls: Open3dWall[],
  angleTolerance = 5,
  mergeDistance = 15,
): void {
  const toRad = (deg: number) => (deg * Math.PI) / 180;
  const normalizeAngle = (a: number) => {
    a = a % (Math.PI * 2);
    if (a > Math.PI) a -= Math.PI * 2;
    if (a <= -Math.PI) a += Math.PI * 2;
    return a;
  };
  const angleDiff = (a: number, b: number) => Math.abs(normalizeAngle(a - b));
  const tolRad = toRad(angleTolerance);

  // Pass 1: Snap near-axis walls
  for (const wall of walls) {
    const dx = wall.end.x - wall.start.x;
    const dy = wall.end.y - wall.start.y;
    const angle = Math.atan2(dy, dx);
    const len = Math.sqrt(dx * dx + dy * dy);
    if (len < 1) continue;

    const snapped = [0, Math.PI / 2, Math.PI, -Math.PI / 2, -Math.PI].find(
      (a) => angleDiff(angle, a) < tolRad,
    );

    if (snapped !== undefined) {
      const mx = (wall.start.x + wall.end.x) / 2;
      const my = (wall.start.y + wall.end.y) / 2;
      const halfLen = len / 2;
      wall.start.x = Math.round(mx - Math.cos(snapped) * halfLen);
      wall.start.y = Math.round(my - Math.sin(snapped) * halfLen);
      wall.end.x = Math.round(mx + Math.cos(snapped) * halfLen);
      wall.end.y = Math.round(my + Math.sin(snapped) * halfLen);
    }
  }

  // Pass 2: Merge nearby endpoints
  mergeWallEndpoints(walls, mergeDistance);
}

/**
 * Merge nearby wall endpoints.
 */
function mergeWallEndpoints(walls: Open3dWall[], mergeDistance: number): void {
  interface Endpoint {
    wall: Open3dWall;
    which: "start" | "end";
  }

  const endpoints: Endpoint[] = [];
  for (const wall of walls) {
    endpoints.push({ wall, which: "start" });
    endpoints.push({ wall, which: "end" });
  }

  const getPoint = (ep: Endpoint): Open3dPoint =>
    ep.which === "start" ? ep.wall.start : ep.wall.end;

  // Union-Find for clustering
  const parent: number[] = endpoints.map((_, i) => i);
  const find = (i: number): number => {
    while (parent[i] !== i) {
      parent[i] = parent[parent[i]];
      i = parent[i];
    }
    return i;
  };
  const union = (a: number, b: number) => {
    parent[find(a)] = find(b);
  };

  // Cluster nearby endpoints
  for (let i = 0; i < endpoints.length; i++) {
    const pi = getPoint(endpoints[i]);
    for (let j = i + 1; j < endpoints.length; j++) {
      const pj = getPoint(endpoints[j]);
      if (Math.sqrt((pi.x - pj.x) ** 2 + (pi.y - pj.y) ** 2) < mergeDistance) {
        union(i, j);
      }
    }
  }

  // Merge clusters
  const clusters = new Map<number, number[]>();
  for (let i = 0; i < endpoints.length; i++) {
    const root = find(i);
    if (!clusters.has(root)) clusters.set(root, []);
    clusters.get(root)!.push(i);
  }

  for (const [, members] of clusters) {
    if (members.length < 2) continue;

    let ax = 0,
      ay = 0;
    for (const idx of members) {
      const p = getPoint(endpoints[idx]);
      ax += p.x;
      ay += p.y;
    }
    ax = Math.round(ax / members.length);
    ay = Math.round(ay / members.length);

    for (const idx of members) {
      const ep = endpoints[idx];
      if (ep.which === "start") {
        ep.wall.start.x = ax;
        ep.wall.start.y = ay;
      } else {
        ep.wall.end.x = ax;
        ep.wall.end.y = ay;
      }
    }
  }
}

/**
 * Import a floor from Apple RoomPlan JSON format.
 * @param jsonData - RoomPlan JSON data
 * @param options - Import options
 * @returns The imported floor
 */
export function importRoomPlan(
  jsonData: Record<string, unknown>,
  options: RoomPlanImportOptions = {},
): Open3dFloor {
  const rpWalls = (jsonData.walls ?? []) as Array<Record<string, unknown>>;
  const rpDoors = (jsonData.doors ?? []) as Array<Record<string, unknown>>;
  const rpWindows = (jsonData.windows ?? []) as Array<Record<string, unknown>>;
  const rpObjects = (jsonData.objects ?? []) as Array<Record<string, unknown>>;
  const rpSections = (jsonData.sections ?? []) as Array<Record<string, unknown>>;

  const floorId = generateId();
  const walls: Open3dWall[] = [];
  const doors: Open3dDoor[] = [];
  const windows: Open3dWindow[] = [];
  const furniture: Open3dFurnitureItem[] = [];
  const rooms: Open3dRoom[] = [];

  // Map RoomPlan wall IDs to our wall IDs
  const wallIdMap = new Map<string, string>();

  // Process walls
  for (const rw of rpWalls) {
    const dims = (rw.dimensions ?? []) as number[];
    const transform = (rw.transform ?? []) as number[];

    if (!dims || dims.length < 2 || !transform || transform.length < 16) continue;
    if (!Number.isFinite(dims[0]) || !Number.isFinite(dims[1])) continue;

    const pos = getPositionFromTransform(transform);
    const angle = getYRotation(transform);
    const halfWidth = (dims[0] / 2) * ROOMPLAN_TO_MM;
    const height = dims[1] * ROOMPLAN_TO_MM;

    // Wall direction from transform
    const wallDirX = transform[0] ?? 1;
    const wallDirZ = transform[2] ?? 0;

    const center = toOurPoint(pos.x, pos.z);
    const start: Open3dPoint = {
      x: center.x - wallDirX * halfWidth,
      y: center.y - wallDirZ * halfWidth,
    };
    const end: Open3dPoint = {
      x: center.x + wallDirX * halfWidth,
      y: center.y + wallDirZ * halfWidth,
    };

    const wallId = generateId();
    wallIdMap.set(String(rw.identifier ?? ""), wallId);

    walls.push({
      id: wallId,
      start,
      end,
      thickness: 150, // 15cm default
      height: Math.round(height),
      color: themeColorRef(PLANNER_COLOR_TOKENS.importWall),
    });
  }

  // Process doors
  for (const rd of rpDoors) {
    const dims = (rd.dimensions ?? []) as number[];
    const transform = (rd.transform ?? []) as number[];

    if (!dims || dims.length < 2 || !transform || transform.length < 16) continue;

    const parentId = String(rd.parentIdentifier ?? "");
    const parentWallId = wallIdMap.get(parentId);
    if (!parentWallId) continue;

    const wall = walls.find((w) => w.id === parentWallId);
    if (!wall) continue;

    const pos = getPositionFromTransform(transform);
    const doorPoint = toOurPoint(pos.x, pos.z);
    const position = projectOntoWall(wall, doorPoint);

    doors.push({
      id: generateId(),
      wallId: parentWallId,
      position,
      width: Math.round(dims[0] * ROOMPLAN_TO_MM),
      height: Math.round(dims[1] * ROOMPLAN_TO_MM),
      type: mapDoorType(rd.category),
      swingDirection: "left",
      flipSide: false,
    });
  }

  // Process windows
  for (const rw of rpWindows) {
    const dims = (rw.dimensions ?? []) as number[];
    const transform = (rw.transform ?? []) as number[];

    if (!dims || dims.length < 2 || !transform || transform.length < 16) continue;

    const parentId = String(rw.parentIdentifier ?? "");
    const parentWallId = wallIdMap.get(parentId);
    if (!parentWallId) continue;

    const wall = walls.find((w) => w.id === parentWallId);
    if (!wall) continue;

    const pos = getPositionFromTransform(transform);
    const winPoint = toOurPoint(pos.x, pos.z);
    const position = projectOntoWall(wall, winPoint);

    windows.push({
      id: generateId(),
      wallId: parentWallId,
      position,
      width: Math.round(dims[0] * ROOMPLAN_TO_MM),
      height: Math.round(dims[1] * ROOMPLAN_TO_MM),
      sillHeight: 900, // 90cm default
      type: mapWindowType(rw.category),
    });
  }

  // Process furniture objects
  for (const ro of rpObjects) {
    const dims = (ro.dimensions ?? []) as number[];
    const transform = (ro.transform ?? []) as number[];

    if (!dims || dims.length < 3 || !transform || transform.length < 16) continue;

    const pos = getPositionFromTransform(transform);
    const angle = getYRotation(transform);

    // Simple catalog ID mapping based on category
    const category = String(ro.category ?? "");
    let catalogId = "chair";
    if (category.includes("sofa") || category.includes("couch")) catalogId = "sofa";
    else if (category.includes("table")) catalogId = "dining_table";
    else if (category.includes("bed")) catalogId = "bed";
    else if (category.includes("storage") || category.includes("cabinet")) catalogId = "storage";

    furniture.push({
      id: generateId(),
      catalogId,
      position: toOurPoint(pos.x, pos.z),
      rotation: (angle * 180) / Math.PI,
      scale: { x: 1, y: 1, z: 1 },
      width: Math.round(dims[0] * ROOMPLAN_TO_MM),
      depth: Math.round(dims[2] * ROOMPLAN_TO_MM),
      height: Math.round(dims[1] * ROOMPLAN_TO_MM),
    });
  }

  // Post-process walls
  const mergeDist = options.mergeDistance ?? 15;
  if (options.straighten !== false) {
    straightenWalls(walls, options.angleTolerance ?? 5, mergeDist);
  }

  // Process sections (rooms)
  for (const rs of rpSections) {
    const label = String(rs.label ?? "");
    rooms.push({
      id: generateId(),
      name: mapSectionLabel(label),
      walls: [],
      floorTexture: "hardwood",
      area: 0,
    });
  }

  return {
    id: floorId,
    name: "Ground Floor",
    level: 0,
    walls,
    rooms,
    doors,
    windows,
    furniture,
    stairs: [],
    columns: [],
    guides: [],
    measurements: [],
    annotations: [],
    textAnnotations: [],
    groups: [],
  };
}

/**
 * Import RoomPlan JSON string.
 */
export function importRoomPlanFromJson(
  jsonString: string,
  options: RoomPlanImportOptions = {},
): { floor: Open3dFloor | null; error: string | null } {
  try {
    const jsonData = JSON.parse(jsonString);
    const floor = importRoomPlan(jsonData, options);
    return { floor, error: null };
  } catch (e) {
    return { floor: null, error: e instanceof Error ? e.message : "Failed to parse RoomPlan JSON" };
  }
}

// ── Format Detection ─-

/**
 * Detect the format of an input JSON string.
 */
export function detectFormat(jsonString: string): FormatDetectionResult {
  try {
    const data = JSON.parse(jsonString);

    // Check for RoomPlan format
    if (data.walls && data.doors && data.sections && !data.project && !data.floors) {
      // Likely RoomPlan
      return { format: "roomplan", confidence: 0.9 };
    }

    // Check for our JSON envelope format
    if (data.type === "open3d-floorplan-project" && data.project) {
      return { format: "json", confidence: 0.95 };
    }

    // Check for older format
    if (data.floors && data.id && data.name) {
      return { format: "json", confidence: 0.7 };
    }

    return { format: "unknown", confidence: 0 };
  } catch {
    return { format: "unknown", confidence: 0 };
  }
}

/**
 * Auto-detect and import based on format.
 */
export function autoImport(
  jsonString: string,
  options?: {
    importLimits?: ImportLimits;
    roomPlanOptions?: RoomPlanImportOptions;
  },
): ImportResult | { floor: Open3dFloor; error?: string } {
  const format = detectFormat(jsonString);

  switch (format.format) {
    case "json":
      return importFromJSON(jsonString, options?.importLimits);

    case "roomplan": {
      const result = importRoomPlanFromJson(
        jsonString,
        options?.roomPlanOptions,
      );
      if (result.floor) {
        return {
          success: true,
          project: {
            id: generateId(),
            name: "Imported Project",
            floors: [result.floor],
            activeFloorId: result.floor.id,
            displayUnit: "mm" as Open3dDisplayUnit,
            createdAt: new Date().toISOString(),
            updatedAt: new Date().toISOString(),
          },
          errors: [],
        };
      }
      return {
        success: false,
        project: null,
        errors: [{ path: "parse", message: result.error ?? "Parse error", severity: "error" }],
      };
    }

    default:
      return {
        success: false,
        project: null,
        errors: [
          { path: "format", message: "Unknown JSON format", severity: "error" },
        ],
      };
  }
}

