      placedFrom: "drag",
      position: { x: 100, y: 200 },
      rotation: 45,
      scale: { x: 2, y: 2, z: 2 },
      materialOverride: "wood",
      colorOverride: "oak",
      locked: true,
    });
    expect(result.placementId).toContain("plc-");
