      tags: [`tag-${i % 5}`, "common"],
      roomTags: [rooms[i % 3]],
      styleTags: [styles[i % 3]],
      dimensions: { widthMm: 400 + i * 10, depthMm: 300 + i * 5, heightMm: 700 + i },
      material: { marketingMaterial: "Wood", normalizedMaterial: ["Wood", "Metal", "Fabric"][i % 3] },
