    expect(CATEGORY_SHAPE_COLORS.Outdoor).toBeDefined();
    expect(CATEGORY_SHAPE_COLORS.Symbols).toBeDefined();
  });

  it("themes use semantic CSS colors instead of hardcoded hex values", () => {
    const hardcodedHexColor = /#[0-9a-f]{3,8}\b/i;
